export const chunk0: Poem[] = [
  { id: 1, title: "关雎",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "关关雎鸠，在河之洲，窈窕淑女，君子好逑",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "关雎", original: `关关雎鸠，在河之洲。窈窕淑女，君子好逑。
参差荇菜，左右流之。窈窕淑女，寤寐求之。
求之不得，寤寐思服。悠哉悠哉，辗转反侧。
参差荇菜，左右采之。窈窕淑女，琴瑟友之。
参差荇菜，左右芼之。窈窕淑女，钟鼓乐之。`, translation: `雎鸠鸟叽叽喳喳地叫，在河中小岛上。那美丽善良的好姑娘，正是小伙子的好对象。
水里的荇菜长长短短，有人左右来回地捞。那美丽善良的好姑娘，醒来睡去都想追求她。
追求她却得不到，白天黑夜心里总挂念。长长的思念啊，躺在床上翻来覆去睡不着。
水里的荇菜长长短短，有人左右把菜采。那美丽善良的好姑娘，我要弹琴鼓瑟亲近她。
水里的荇菜长长短短，有人左右把菜摘。那美丽善良的好姑娘，我要敲钟打鼓让她开心。`, interpretation: `《关雎》是《诗经》的开篇之作，距今已有两千多年，是我国最早的诗歌总集里的第一首。那时候的人们用简单纯朴的歌声表达感情。诗中有一个特别有趣的小细节：雎鸠鸟。这种鸟总是成双成对地生活，古人看见它们恩爱的样子，就想到了人间美好的爱情。整首诗最妙的地方在于"求之不得，寤寐思服。悠哉悠哉，辗转反侧"——喜欢一个人却得不到，夜里翻来覆去睡不着，这种感觉两千年前的少年和今天的你，是不是一模一样呢？最后，小伙子想出了办法：用琴瑟、钟鼓去亲近心爱的姑娘，让爱情变得热闹又美好。这首温柔的小诗，就这样一代代传了下来。` }] },
  { id: 2, title: "蒹葭",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "蒹葭苍苍，白露为霜，所谓伊人，在水一方",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "蒹葭", original: `蒹葭苍苍，白露为霜。所谓伊人，在水一方。溯洄从之，道阻且长。溯游从之，宛在水中央。
蒹葭萋萋，白露未晞。所谓伊人，在水之湄。溯洄从之，道阻且跻。溯游从之，宛在水中坻。
蒹葭采采，白露未已。所谓伊人，在水之涘。溯洄从之，道阻且右。溯游从之，宛在沚。`, translation: `芦苇青青又苍苍，露水变成了白霜。我心里想念的那个人，就在河水的那一边。逆着水流去找她，路又远又难走；顺着水流去找她，她好像就在河水中间。芦苇长得真茂盛，露水还没干呢。我心里想念的那个人，就在水草边。逆着水流去找她，路又远又高；顺着水流去找她，她好像就在水中的小岛上。`, interpretation: `这是两千多年前《诗经》里的一首小歌，写的是秋天清晨，芦苇上挂着白霜，一位小伙子站在河边想念他心爱的姑娘。隔着一条河，看得见却到不了，越追越觉得她飘忽不定——这就是诗里最迷人的“伊人”意象。整首诗三次重复“溯洄”“溯游”，像是在说：明知道够不着，却还是想去找。这份执着的思念，后来成了中国人表达“求而不得”的经典名句，影响了无数诗词。` }] },
  { id: 3, title: "采薇（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "昔我往矣，杨柳依依，今我来思，雨雪霏霏",
    tags: "诗经,战争",
    color: "#d97706",
    sections:[    { id: 1, title: "采薇（节选）", original: `昔我往矣，杨柳依依。今我来思，雨雪霏霏。
行道迟迟，载渴载饥。我心伤悲，莫知我哀。`, translation: `同学们，我们接着来读《采薇》最后几句。回想当初我离家出征的时候，正是春天，杨柳柔软的长枝随风轻轻摇摆，好像在跟我依依不舍地道别。'依依'这个词用得真好，把杨柳的姿态写得又柔美又温柔，也悄悄透露出战士离别时心头的那份留恋。可是现在我终于盼到回家的这一天了，眼前看到的却是冬天，大雪纷纷扬扬地飘落下来，天气又冷又暗。回家的路还长得很呢，我走啊走，走得又慢又累，一路上又渴又饿，浑身难受。这句写得好，用'迟迟'两个字，把归途的艰难和疲倦全写出来了。我心里头真是又苦又悲伤，可身边没有一个人能真正懂得我的哀伤啊。`, interpretation: `这首诗出自《诗经》，大约写于两千多年前的西周时期。当时周朝经常和外族打仗，许多士兵被迫离开家乡，一去就是好多年。这段话是一位老兵回家路上的心声——他想起离家时春天杨柳轻柔的模样，对比现在归来时漫天风雪的凄凉，路又远又累，心里满是委屈，可跟谁说呢？短短几句，有景有情，特别是“杨柳依依”和“雨雪霏霏”两个画面，一美一惨，对比强烈，成了千古名句。后来人们写离别、写思乡，常常会想起这两句呢！` }] },
  { id: 4, title: "桃夭",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "桃之夭夭，灼灼其华，之子于归，宜其室家",
    tags: "诗经,婚嫁",
    color: "#d97706",
    sections:[    { id: 1, title: "桃夭", original: `桃之夭夭，灼灼其华。之子于归，宜其室家。
桃之夭夭，有蕡其实。之子于归，宜其家室。
桃之夭夭，其叶蓁蓁。之子于归，宜其家人。`, translation: `桃树长得真年轻啊，开出的花朵红艳艳亮堂堂。这个姑娘要出嫁啦，和和美美一家人！桃树长得真年轻啊，枝头果实肥又大。这个姑娘要出嫁啦，全家和睦乐开花！桃树长得真年轻啊，树叶茂盛密麻麻。这个姑娘要出嫁啦，婆家老少都爱她！`, interpretation: `这首诗来自两千多年前的《诗经》，是古人在婚礼上唱的祝福歌。那时候没有鲜花和彩带，人们就指着院子里盛开的桃树，为新娘送上最美的祝愿。诗里反复写桃树——桃花鲜红、果实饱满、绿叶繁茂，象征新娘青春美丽、多子多福、家庭兴旺。整首诗只有短短几句话，却有四组重叠，读起来像欢快的歌声，特别适合婚礼上一起唱。它是中国最早祝贺新娘的诗，后来人们说'桃之夭夭，灼灼其华'，都用来形容春天和美丽的事物呢！` }] },
  { id: 5, title: "静女",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "静女其姝俟我于城隅爱而不见搔首踟蹰",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "静女", original: `静女其姝，俟我于城隅。爱而不见，搔首踟蹰。
静女其娈，贻我彤管。彤管有炜，说怿女美。
自牧归荑，洵美且异。匪女之为美，美人之贻。`, translation: `温柔漂亮的姑娘啊，约我等在城墙角。
她故意躲起来不露面，让我挠着头来回走。
温柔漂亮的姑娘啊，送我一支红红的笛管。
红笛颜色亮晶晶，我呀越看越喜欢。
她从郊外采来嫩茅草送我，这草儿真美丽又稀奇。
并不是茅草有多好，只因为它是美人亲手送我的。`, interpretation: `这首诗来自两千多年前的《诗经》年代，那时候的年轻人也会偷偷约会呢！全诗讲了一个甜蜜的小故事：一位漂亮的姑娘和小伙子约好在城墙边见面，结果姑娘调皮地藏了起来，小伙子急得抓耳挠腮。姑娘出现后，送了他一支红笛管和一根野草，这些在别人看来普通的小东西，因为是心爱之人送的，就变得无比珍贵啦！诗中最妙的就是最后那句'匪女之为美，美人之贻'——东西好不好不重要，重要的是谁给的。这种'礼物因为心意而珍贵'的想法，到现在还常常被人们说起，是中国最早的'爱情小品文'之一，读起来就像在看一出可爱的古代偶像剧！` }] },
  { id: 6, title: "子衿",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "青青子衿悠悠我心纵我不往子宁不嗣音",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "子衿", original: `青青子衿，悠悠我心。纵我不往，子宁不嗣音？
青青子佩，悠悠我思。纵我不往，子宁不来？
挑兮达兮，在城阙兮。一日不见，如三月兮`, translation: `你那青青的衣领啊，悠悠地挂在我心头。纵然我今天没去找你，你怎么能就不给我捎个信儿呢？你那青青的佩玉啊，悠悠地让我思念不已。纵然我今天没去找你，你怎么能就不来看我呢？我独自走来走去啊，就在那高高的城楼上张望。一天没见到你啊，就像隔了三个月那么漫长！`, interpretation: `这首诗出自两千多年前的《诗经》，是一位姑娘在等心上人时唱的歌。那时候的女孩子思念情郎，会跑到城楼上去张望，越等越心焦。诗里用'青青'形容衣领和佩玉，色彩明亮又温柔，读着就好像看到了那位翩翩少年。'一日不见，如三月兮'是千古名句，把等待的滋味写得特别传神——才一天没见，感觉比三个月还久呢！小朋友，你有没有过等一个人、等得很焦急的时候？那就懂这位姑娘的心情啦！` }] },
  { id: 7, title: "无衣",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "岂曰无衣，与子同袍，王于兴师，修我戈矛，与子同仇",
    tags: "诗经,战争",
    color: "#d97706",
    sections:[    { id: 1, title: "无衣", original: `岂曰无衣？与子同袍。王于兴师，修我戈矛。与子同仇。
岂曰无衣？与子同泽。王于兴师，修我矛戟。与子偕作。
岂曰无衣？与子同裳。王于兴师，修我甲兵。与子偕行。`, translation: `谁说我们没有衣裳？我和你披同一件战袍！国王要出兵打仗了，快把我们的戈和矛修好，我和你一起对付敌人！谁说我们没有衣裳？我和你穿同一件内衣！国王要出兵打仗了，快把我们的矛和戟修好，我和你一起行动！谁说我们没有衣裳？我和你穿同一条下裳！国王要出兵打仗了，快把我们的铠甲和兵器修好，我和你一起上战场！`, interpretation: `这首诗来自两千多年前的《诗经》，是秦国的一首军歌。当时战乱频繁，百姓要上战场打仗，战士们之间结下了深厚的情谊。诗中反复吟唱'与子同袍''与子同泽''与子同裳'，'袍、泽、裳'是贴身的衣物，说明战士们亲如兄弟、同生共死。最有趣的是它的问答结构——先说'谁说没衣穿'，马上回答'我和你共用'，特别有气势！这首战歌短小有力，读起来像激昂的口号，后来很多诗人都受到它的影响，比如那句'与子同袍'，至今还被人们用来形容朋友间的深厚情谊呢！` }] },
  { id: 8, title: "氓（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "氓之蚩蚩，抱布贸丝，匪来贸丝，来即我谋",
    tags: "诗经,叙事",
    color: "#d97706",
    sections:[    { id: 1, title: "氓（节选）", original: `氓之蚩蚩，抱布贸丝。匪来贸丝，来即我谋。
送子涉淇，至于顿丘。匪我愆期，子无良媒。
桑之未落，其叶沃若。于嗟鸠兮，无食桑葚。
于嗟女兮，无与士耽。士之耽兮，犹可说也。
女之耽兮，不可说也`, translation: `那个男人笑嘻嘻的，抱着布来换我的丝。他哪里是来换丝啊，分明是来找我商量婚事的。我送你渡过淇水，一直送到顿丘。不是我拖延婚期，是你没有找好媒人。桑树叶子还没落的时候，叶子绿油油、水灵灵的。哎呀，斑鸠啊，可别贪吃桑葚！哎呀，姑娘啊，可别对男人太迷恋！男人要是迷上了你，还能脱身；姑娘要是迷上了他，可就难摆脱啦！`, interpretation: `这首诗来自两千多年前的《诗经》，讲的是一个姑娘回忆自己被负心汉欺骗的故事。那时候女孩子不能自己找对象，全靠媒人牵线，规矩可严啦！姑娘用斑鸠吃桑葚会醉倒来打比方，温柔地提醒其他女孩：爱情里要清醒呀！这是中国最早的“弃妇诗”，语言像唱歌一样好听，比喻新鲜又贴切，连后来写《长恨歌》的白居易，都从这儿学了不少表达情感的技巧呢！` }] },
  { id: 9, title: "击鼓（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "死生契阔，与子成说，执子之手，与子偕老",
    tags: "诗经,战争",
    color: "#d97706",
    sections:[    { id: 1, title: "击鼓（节选）", original: `击鼓其镗，踊跃用兵。土国城漕，我独南行。
死生契阔，与子成说。执子之手，与子偕老。
于嗟阔兮，不我活兮`, translation: `同学们，我们来读一读这首《击鼓》。它出自《诗经》，是一位远征的士兵写下的思乡思家之诗。战鼓敲得咚咚响，士兵们奋勇练刀枪，整装待发要去打仗。他们忙着修筑漕城来保卫家乡，可是唯独我被派往遥远的南方。一边是战争的号令，一边是心里的牵挂，于是诗人想起了和亲人立下的誓言：生死分离、聚散无常，当初我们约定，要牵着你的手，和你一起白头到老。这句写得好啊，短短一句话，却道出了人间最深的温情。然而现实是残酷的，诗人只能长叹一声：唉，如今你我相隔太远，真是让我活不下去啊！这句话正是全诗最动人之处，它让我们明白，和平与团圆多么值得珍惜。`, interpretation: `这首诗来自两千多年前的春秋时期，写的正是普通士兵远征时的哭诉。那时候战乱频繁，战士们被迫离开家乡和亲人。诗中最打动人的，就是'死生契阔，与子成说。执子之手，与子偕老'这十六个字——它本来是战士对妻子的誓言，却成了中国人对爱情最美好的承诺，千百年来被无数人传诵。短短几句，没有华丽辞藻，却让人读得眼眶发酸，这就是《诗经》的魅力。` }] },
  { id: 10, title: "黍离（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "彼黍离离彼稷之苗知我者谓我心忧不知我者谓我何求",
    tags: "诗经,感怀",
    color: "#d97706",
    sections:[    { id: 1, title: "黍离（节选）", original: `彼黍离离，彼稷之苗。行迈靡靡，中心摇摇。
知我者，谓我心忧。不知我者，谓我何求。
悠悠苍天，此何人哉`, translation: `同学们，我们来读一读这首《黍离》。你看那小米（黍）长得一排排，穗子沉甸甸的；你看那高粱（稷）的苗儿正青葱茂盛。诗人却慢悠悠地往前走啊（行迈靡靡），脚步迟缓沉重，心里头乱得像风中的禾苗一样，摇摇晃晃、忐忑不安。懂我的人啊，知道我心里满是忧愁（谓我心忧）；不懂我的人啊，还以为我在寻找什么东西（谓我何求）。于是他仰头呼喊：悠悠苍天啊，这样无边的痛苦，到底是谁造成的呢？`, interpretation: `这首诗来自两千多年前的西周，那时候周王朝被犬戎攻破都城镐京，迁都洛阳。有一位大夫路过旧都宗庙，看到曾经种粮食的田地全长满了野草，心里特别难受，就写下了这首诗。诗里最妙的就是'黍'和'稷'，就是小米和高粱，本来是种给人吃的粮食，现在却乱蓬蓬地长着没人管，好像在悄悄说：这里的人去哪儿了？'中心摇摇'四个字特别传神，'摇摇'就是心里七上八下、晃晃悠悠的意思，比说'我很伤心'生动多了。后来人们说的'黍离之悲'，就是从这儿来的，专门指对故国、故都的怀念。` }] },
  { id: 11, title: "离骚（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "路漫漫其修远兮，吾将上下而求索",
    tags: "楚辞,经典",
    color: "#d97706",
    sections:[    { id: 1, title: "离骚（节选）", original: `长太息以掩涕兮，哀民生之多艰。
亦余心之所善兮，虽九死其犹未悔。
路漫漫其修远兮，吾将上下而求索`, translation: `同学们，我们来读一读屈原《离骚》中的名句。屈原是两千多年前楚国的大诗人，他心里装着百姓的苦与国家的难。"长太息以掩涕兮"——我长长地叹了一口气，擦去脸上流下的眼泪。"哀民生之多艰"——多么令人悲伤啊，百姓的生活充满了艰难和辛酸！这句写得好，短短六个字就把诗人对人民的同情写了出来。"亦余心之所善兮，虽九死其犹未悔"——只要是我心中真正喜爱的东西，哪怕是死上九回，我也绝不后悔。这里说的是诗人坚持美好品格、九死不悔的决心，十分感人。最后一句"路漫漫其修远兮"——前面的道路啊，又长又远，我还要继续努力去追求。它告诉我们：追求理想的路虽然漫长，但绝不能停下脚步。`, interpretation: `这两句出自屈原的《离骚》。屈原生活在战国时期的楚国，当时朝廷奸臣当道，百姓生活困苦。他虽然被流放，却依然忧国忧民。"太息掩涕"写出了诗人对人民苦难的深深同情，"九死未悔"表现了他坚持理想、绝不妥协的高尚品格。这句话常被后人引用，成为形容执着追求理想的经典名句。` }] },
  { id: 12, title: "湘夫人（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "袅袅兮，秋风洞庭波兮",
    tags: "楚辞,神话",
    color: "#d97706",
    sections:[    { id: 1, title: "湘夫人（节选）", original: `帝子降兮，北渚。
目眇眇兮，愁予。
袅袅兮秋风，洞庭波兮木叶下。
沅有芷兮，澧有兰。
思公子兮，未敢言`, translation: `同学们，我们来读一读这首《湘夫人》。它是战国时期楚国诗人屈原的作品，写在《九歌》里，讲述的是湘水之神之间思念相约的故事。公主降临在北面的沙洲上啊，我远远地望着她，心里满是惆怅。这句写得好，一个“降”字，把神女从天而落的情景写得轻盈又庄严。秋风轻轻地吹起来，洞庭湖泛起层层波涛，岸边的树叶纷纷飘落。这句“袅袅兮秋风，洞庭波兮木叶下”是千古名句，写尽了秋天的苍凉与思念。沅水边长着清香的草白芷啊，澧水边盛开着芬芳的兰花，草木都有自己美好的姿态，而我却深深地想念着你啊，公子！整首诗用秋景衬托相思，读来令人感动。`, interpretation: `这是战国时期楚国大诗人屈原写的《九歌》中的一篇，传说楚地百姓祭祀湘水神时所唱的歌。诗中的湘夫人是传说中舜帝的两个妃子——娥皇和女英，她们泪染青竹，成了湘水之神。诗里写秋风、落叶、白芷、幽兰，处处透着一种凄美又浪漫的气息。屈原最厉害的地方，就是把神话故事和自然景色揉在一起，让人读着读着，就像走进了一幅画。这首诗里'袅袅兮秋风，洞庭波兮木叶下'特别有名，连李白都忍不住模仿它呢！` }] },
  { id: 13, title: "橘颂（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "后皇嘉树橘徕服兮，受命不迁生南国兮，苏世独立横而不流兮",
    tags: "楚辞,咏物",
    color: "#d97706",
    sections:[    { id: 1, title: "橘颂（节选）", original: `后皇嘉树，橘徕服兮。
受命不迁，生南国兮。
深固难徙，更壹志兮。
绿叶素荣，纷其可喜兮。
苏世独立，横而不流兮`, translation: `天地间美好的橘树啊，生来就适应这片土地。它接受了天命的安排，永远扎根在南方，绝不迁移。根深叶茂，难以移植，志向专一坚定。绿色的叶子，洁白的花朵，繁盛美丽真让人喜爱。它清醒地独立于世，横立水中却不被冲走改变方向。`, interpretation: `这首诗是屈原年轻时的作品，写于楚国（大约现在的湖南、湖北一带）。当时楚国盛产橘子，屈原借橘树来表达自己志向。《橘颂》是中国文学史上第一篇完整的咏物诗，'后皇嘉树'四字奠定了橘树的高洁形象。他写橘树的'深固难徙'、'苏世独立'，其实是在说自己要做一个品行坚定、清醒独立的人。后世许多诗人都从这首诗里学到了'借物言志'的写法，比如曹植的《七步诗》就受其影响。整首诗读起来，就像一个小朋友在认真介绍自己的好朋友呢！` }] },
  { id: 14, title: "国殇（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "诚既勇兮，又以武终刚强兮，不可凌身既死兮，神以灵魂魄毅兮",
    tags: "楚辞,战争",
    color: "#d97706",
    sections:[    { id: 1, title: "国殇（节选）", original: `操吴戈兮，被犀甲。
车错毂兮，短兵接。
旌蔽日兮，敌若云。
矢交坠兮，士争先。
诚既勇兮，又以武终。
刚强兮，不可凌。
身既死兮，神以灵。
魂魄毅兮，为鬼雄`, translation: `手持锋利的吴戈啊，身披坚固的犀牛甲。战车轮毂交错在一起啊，短兵器相接敌我厮杀。大旗遮蔽了太阳啊，敌人像云一样涌来。乱箭纷纷坠落啊，战士们个个奋勇争先。真是既勇敢啊，又有武力，性情始终刚强啊，敌人不可欺凌。身体已经死去啊，精神依然不灭。魂魄坚毅啊，永不消亡。`, interpretation: `这首诗是屈原为楚国牺牲的将士们写的一首英雄赞歌，写在战国时期楚国战败之后。诗中有两个特别有气势的意象：一个是“旌蔽日”，大旗多得把太阳都遮住了，说明军队人数众多；一个是“敌若云”，敌人像乌云一样密密麻麻压过来，写出了战斗的紧张可怕。这首《国殇》最大的艺术特色是节奏感很强，句子短而有力，读起来像战鼓一样咚咚响，让人热血沸腾。后来人们常用“国殇”来指代为国牺牲的英雄，这首诗也成为祭祀英烈时最常被朗诵的作品。` }] },
  { id: 15, title: "易水歌",
    author: "荆轲",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "风萧萧兮，易水寒壮士一去兮",
    tags: "先秦,经典",
    color: "#d97706",
    sections:[    { id: 1, title: "易水歌", original: `风萧萧兮易水寒，
壮士一去兮不复还`, translation: `风呼呼地吹过来，声音又长又响，像是在呜呜地哭一样，易水河上的水被吹得冰冰凉凉的。就在这样一个寒冷又让人心里发紧的地方，有一位勇敢的大英雄，名字叫荆轲，他就要出发去做一件非常危险的大事——要去刺杀欺负燕国的坏国王。他心里很清楚，这一走，就像箭射出去一样，再也不可能回来了，可他一点都不害怕，脚步稳稳地往前迈去，因为他知道，自己是为了保护自己的国家而战的，就算回不来，也值得。`, interpretation: `这是两千多年前战国末年的故事。燕国太子丹派刺客荆轲去秦国行刺暴君嬴政，临走前大家都来送行。荆轲在高台上唱起这首歌，易水河边秋风凛冽，他明知此去凶多吉少，却毫不退缩。这两句一写冷风寒水，一写壮士豪情，用“萧萧”形容风声，仿佛连天地都在为他送别。后人常用“风萧萧兮易水寒”形容悲壮豪迈的离别场景，连大英雄项羽都从中借用了这种气势呢！` }] },
  { id: 16, title: "越人歌",
    author: "佚名",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "山有木兮，木有枝心悦君兮",
    tags: "先秦,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "越人歌", original: `今夕何夕兮，搴舟中流。
今日何日兮，得与王子同舟。
蒙羞被好兮，不訾诟耻。
心几烦而不绝兮，得知王子。
山有木兮木有枝，心悦君兮君不知`, translation: `今天究竟是怎样一个美好的夜晚呀，我竟划着小船来到了河中央。今天又到底是什么好日子呀，我竟然有幸能和王子的船靠在一起，与他同坐一条船。你看那高高的山上有树木呀，树木上又长着无数的枝条；可是我心里这样深深喜欢着你呀，这份情意你却一点也不知道呢。这句写得好——前面三句都在讲山、树、枝，好像只是写眼前看见的风景，其实是用“枝”字来暗暗对比“知”字：有枝却不知，借着眼前的小景，说出了心里藏不住的大秘密，把满腔的欢喜和一点点委屈都说尽了。这就是《越人歌》的动人之处，短短几句，却藏着最真最纯的心意。`, interpretation: `这首诗来自遥远的春秋战国时期，是一位划船的越族姑娘唱给楚国王子听的歌，是中国最早的情诗之一。姑娘用山和树打比方——山上有树，树上有枝，这是大家都知道的事；可我喜欢你，你却不知道，多让人着急呀！这种"明明很简单，旁人一看就懂，唯独当事人不知道"的小心思，是不是很像你偷偷喜欢班上的某个同学？全诗只有四句，却把少女怦然心动、想表白又不敢说的小委屈写得特别动人。两千多年过去了，现在我们说"山有木兮木有枝"，大家还是会想起这个勇敢又害羞的越国姑娘。` }] },
  { id: 17, title: "击壤歌",
    author: "佚名",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "日出而作日入而息凿井而饮耕田而食帝力于我何有哉",
    tags: "先秦,民歌",
    color: "#d97706",
    sections:[    { id: 1, title: "击壤歌", original: `日出而作，日入而息。
凿井而饮，耕田而食。
帝力于我何有哉`, translation: `同学们，我们来读一读这首古老而有趣的《击壤歌》。它的意思是：太阳升起来的时候，就出门去地里干活；太阳落山的时候，就回到家里面安安稳稳地休息。天气热了口渴了，就在土地上凿一口井，捧起清凉的井水咕咚咕咚喝下去；到了秋天庄稼成熟了，亲手耕种出粮食，就能吃上香喷喷的饭。这句写得好，前面讲的劳动和生活多么自由自在啊！最后一句更有意思了：帝王再了不起，又与我有什么关系呢？这句话表达了古代百姓自食其力、安居乐业的快乐心情，也体现了不慕权贵、朴素知足的高尚情怀。`, interpretation: `这是流传了两千多年的古老民歌，据说是一位老人在田间边唱歌边用木块打着节拍，所以叫《击壤歌》。它诞生在很遥远的先秦时期，那时候普通人过着简单纯朴的日子，歌词里“日出”“日入”“凿井”“耕田”这些画面，就像一幅农家生活图，特别亲切。最有意思的是最后一句“帝力于我何有哉”，意思是我靠自己劳动就能吃饱喝足，帝王跟我有啥关系呢？这句话里藏着一股子自豪和自由劲儿，后世很多人读到都会心一笑，觉得这老头真酷！所以它也被看作中国最早表达平民自得其乐、不慕权贵的诗篇之一。` }] },
  { id: 18, title: "卿云歌",
    author: "佚名",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "卿云烂兮，纠缦缦兮，日月光华旦复旦兮",
    tags: "先秦,颂歌",
    color: "#d97706",
    sections:[    { id: 1, title: "卿云歌", original: `卿云烂兮，纠缦缦兮。
日月光华，旦复旦兮`, translation: `同学们，我们来读一读这首古老的《卿云歌》。相传它是上古时期流传下来的歌谣，人们用它来赞美天上的祥云与日月，表达对光明和美好生活的向往。

先看第一句：“卿云烂兮”，卿云就是五彩的祥云，“烂”是明亮、灿烂的意思，整句话是说：看啊，那五彩的祥云多么明亮、多么绚丽啊！

接着读第二句：“纠缦缦兮”，“纠”是缠绕、联结的样子，“缦缦”形容云层舒展绵长，连在一起就是：云朵层层叠叠，自由舒展，绵延不断地飘荡在天空！

再看第三句：“日月光华”，意思是太阳和月亮的光辉多么灿烂夺目，照耀着大地万物。这句写得好，短短四字就把天地间最明亮的光都写出来了。

最后一句：“旦复旦兮”，意思是光明啊，一天接着一天，永远循环不断。

整首诗歌颂了大自然的光明与美好，也寄托了古人对幸福生活绵延不绝的期盼，读来让人心中充满希望。`, interpretation: `这首歌传说是上古时代虞舜在位时，君臣齐唱的歌谣，距今已有四千多年啦！它描绘了天空中华丽的彩云和灿烂的日月，表达了对太平盛世的赞美与祝福。短短三句话里，云、光、日、月交织成一幅明亮祥和的画面，节奏明快，读起来朗朗上口。后来人们常说的“日月光华”“复旦”这些词都从这里来的，意思是光明不断重现，美好永远延续。这首歌也入选了语文课本，是小朋友们认识上古诗歌的好起点哦！` }] },
  { id: 19, title: "天问（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "遂古之初，谁传道之，上下未形，何由考之",
    tags: "楚辞,哲理",
    color: "#d97706",
    sections:[    { id: 1, title: "天问（节选）", original: `遂古之初，谁传道之？
上下未形，何由考之？
冥昭瞢暗，谁能极之？
明明暗暗，惟时何为？
阴阳三合，何本何化？
圆则九重，孰营度之？`, translation: `远古最开始的时候，是谁把那些事情传说讲述？天和地还没有成形，那时候的情况怎么去考察清楚？天地一片混沌昏暗，谁能够追根究底问个明白？光明和黑暗交替出现，这到底是因为什么？阴阳二气融合在一起，哪个是本源，哪个又变成了这样？`, interpretation: `这首诗来自两千多年前战国时期的楚国，是大诗人屈原写的《天问》。那时候的人们对天地宇宙充满好奇，却又没有科学答案。屈原就像一个爱提问的小学生，对着苍天一口气问了很多大问题——天是谁造的？地是怎么来的？白天黑夜为什么交替？这些奇思妙想后来被称作'天问'，连大文豪鲁迅都称赞，说屈原敢向天发问，脑子真厉害！这首诗里的'冥昭瞢暗'四个字特别形象，写出了天地未分时那种又暗又亮、模模糊糊的样子。屈原这种爱思考、爱追问的精神，一直影响到今天，我们每个人都可以像他一样，做一个勇敢的'小问号'！` }] },
  { id: 20, title: "河广",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "谁谓河广，一苇杭之，谁谓宋远，跂予望之",
    tags: "诗经,思乡",
    color: "#d97706",
    sections:[    { id: 1, title: "河广", original: `谁谓河广？一苇杭之。
谁谓宋远？跂予望之。
谁谓河广？曾不容刀。
谁谓宋远？曾不崇朝`, translation: `谁说黄河又宽又大？其实一根小小的芦苇就能渡过河去。谁说宋国离这儿很远？只要踮起脚尖、抬起头来，就能远远望见。谁说黄河又宽又大？它其实窄得很，连一只小船都放不下。谁说宋国离这儿很远？快快走去，用不了一个早晨就能到达。同学们，这首短短的诗用四个“谁谓”——也就是四个反问——告诉我们一个道理：阻挡你的从来不是山河的距离，而是心中那层不想回去的念头。`, interpretation: `这首诗来自两千多年前的《诗经》，是一位住在卫国的人思念家乡宋国时写的。他心里太想家了，所以觉得黄河根本不宽，宋国根本不远。其实呀，黄河又宽又深，宋国也隔着千山万水呢！诗里用了一连串的反问“谁谓”，像是在跟人争辩，特别有童趣。叠句和反问的写法让思乡之情又急切又可爱，也让我们看到：想家的时候，距离好像都能被爱拉近。这首小诗虽然短，却被后人传诵了两千多年呢。` }] },
  { id: 21, title: "君子于役",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "君子于役，不知其期，鸡栖于埘，日之夕矣，羊牛下来",
    tags: "诗经,思念",
    color: "#d97706",
    sections:[    { id: 1, title: "君子于役", original: `君子于役，不知其期。
曷至哉？鸡栖于埘。
日之夕矣，羊牛下来。
君子于役，如之何勿思`, translation: `同学们，我们来读一读这首《君子于役》。这是一首妻子思念远方服役丈夫的诗，写得十分动人。下面我们一句一句地来理解。

第一句“君子于役，不知其期”：君子，这里是妻子对丈夫的尊称；于役，是说丈夫去外面服劳役了。意思是，丈夫去远方服劳役了，不知道什么时候才能回家。

第二句“鸡栖于埘，日之夕矣”：栖，就是回窝休息；埘，读shí，是指墙上挖的鸡窝。意思是，鸡儿已经飞回墙上的窝里，太阳也快要落下山去了。

第三句“羊牛下来”：是说山坡上的羊儿和牛儿，也都陆续地赶着回家了。

第四句“君子于役，如之何勿思”：如之何，就是怎么能；勿思，是不思念。意思是，丈夫还在远方服劳役，看到这黄昏归家的景象，叫我怎么能不思念他呢？

这句写得好：诗中没有一句直接说“我想你”，却用鸡回窝、牛羊下山的归家画面，反衬出丈夫不能归来的孤独。读到这里，你是不是也感受到妻子心中那份深深的牵挂了呢？`, interpretation: `这首诗来自两千多年前的春秋时期，那时候男子要去远方服兵役或劳役，一去就不知道什么时候能回家。诗中一位女子在傍晚时分，看着鸡回窝、牛羊下山的景象，心里特别想念远方的丈夫。傍晚是回家团聚的时刻，可她的丈夫不在身边，这让她更觉得孤单。最有意思的是，诗里没有直接说'我很想他'，而是通过描写鸡、牛、羊都回家了，反衬出丈夫还没归来的遗憾，这就是古诗常用的'反衬'手法。读起来亲切温柔，像是我们自己的妈妈在门口盼着爸爸下班回来一样，让人心里暖暖的又酸酸的。` }] },
  { id: 22, title: "木瓜",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "投我以木瓜报之以琼琚匪报也永以为好也",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "木瓜", original: `投我以木瓜，报之以琼琚。
匪报也，永以为好也。
投我以木桃，报之以琼瑶。
匪报也，永以为好也。
投我以木李，报之以琼玖。
匪报也，永以为好也`, translation: `同学们，我们来读一读这首古老的诗篇《木瓜》。这是一首流传千年的友谊之歌，告诉我们：朋友之间送礼物，珍贵的不在于东西本身，而在于那份真挚的心意。让我们先看第一句："你送给我一个木瓜，我就拿精美的玉佩来回报你。"这里要注意，诗里的"木瓜"并不一定是真的果子，它代表朋友之间小小的赠礼；而"琼琚"指的是华美的玉石饰品，价值远远超过木瓜。紧接着一句写得好："这不是简单的回礼啊，是希望我们永远相好呀！"告诉我们，真正的友谊，不是计较礼物贵贱，而是借此表达珍惜对方、长相陪伴的心愿。后两句意思一样，只是把"木瓜"换成了"木桃"，把"琼琚"换成了"琼瑶"，反复吟唱，表达了朋友之间情谊长存、永以为好的美好愿望。`, interpretation: `这首诗来自两千多年前的《诗经》,是古代青年男女互赠定情信物时唱的歌。姑娘送小伙子木瓜、桃子这样普通的水果,小伙子却回赠珍贵的美玉——这说明在他心中,姑娘的情意比美玉还宝贵呀!诗中最有意思的地方是"匪报也"三个字,意思是"这哪里是报答"。古人不像我们现在说话这么直白,他们用反复吟唱"永以为好也"来表达心意,既含蓄又深情。后来"投桃报李"这个成语就是从这儿来的,比喻朋友之间互相赠送礼物、礼尚往来。读这首诗的时候,你能感受到古人表达爱情的方式多么温柔又真诚呢!` }] },
  { id: 23, title: "采葛",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "彼采葛兮，一日不见如三月兮",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "采葛", original: `彼采葛兮，一日不见如三月兮。
彼采萧兮，一日不见如三秋兮。
彼采艾兮，一日不见如三岁兮。`, translation: `同学们，我们来读一读这首《采葛》。这是一首两千多年前写的小诗，讲的是一个人想念他心爱姑娘的那种又甜蜜又焦急的心情。我们一句一句来看：那个采葛（一种藤蔓植物）的姑娘啊，一天没有见到她，就好像过了三个月那么漫长；那个采萧（祭祀用的香草）的姑娘啊，一天没见，就像隔了三个季节；那个采艾（艾草）的姑娘啊，一天没见，就像整整三年都没见面一样。这句写得好——诗人用三个月、三季、三年一次比一次长的时间，来表达心里那份越来越强烈的思念。原来古人和我们一样，也会因为想念一个人而觉得时间走得特别慢呀。`, interpretation: `这首诗来自两千多年前的春秋时期，是一位小伙子在唱给心上人听的歌。那时候人们采集葛草、萧草、艾草来生活，小伙子借这些常见的事儿来想念那个采草的姑娘。他用“一天不见”开头，却越说越长——三个月、三季、三年，时间像被想念拉长了一样！这就叫“夸张”，越夸张越说明想得厉害。整首诗只有几句话，却把热恋中“度日如年”的心情写活了，后来人们形容思念特别深，还常常会想到这首诗呢。` }] },
  { id: 24, title: "月出",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "月出皎兮，佼人僚兮，舒窈纠兮，劳心悄兮",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "月出", original: `月出皎兮，佼人僚兮，舒窈纠兮，劳心悄兮。
月出皓兮，佼人懰兮，舒忧受兮，劳心慅兮。`, translation: `同学们，《月出》是《诗经·陈风》里一首非常美的月下恋歌，描写一位男子在月光下思念心上人的情景。我们来读一读：月亮出来亮堂堂啊，那位美人真漂亮啊。身姿轻盈又苗条啊，我的心儿好忧伤啊。月亮出来多明亮啊，那位美人真秀丽啊。体态舒缓又柔美啊，我的心儿乱晃晃啊。这首诗一共四章，每章只有短短四句，却句句动人。开头“月出皎兮”，皎就是洁白明亮的意思，一个“皎”字，仿佛让银白的月光洒在我们眼前。接着“佼人僚兮”，佼人就是美人，僚是漂亮的意思，诗人望着月亮，想起了那位美丽的姑娘。“舒窈纠兮”写姑娘走路的样子，舒是舒缓，窈纠是身材苗条优美的样子，这句写得好，一个“舒”字把女子轻盈柔美的姿态写活了。最后“劳心悄兮”，劳心的意思是使人忧愁，悄是悄悄忧愁的样子，整首诗就在这份淡淡的相思中结束，让人回味无穷。`, interpretation: `这首诗来自两千多年前的《诗经·陈风》，是古人写给心上人的"小情歌"。皎洁的月光下，诗人偷偷望着美丽的姑娘，越看越喜欢，心里却像小鹿乱撞，又甜又慌。诗中最妙的就是"月出"和"美人"交相辉映——月亮越亮，姑娘越美，诗人的心越乱。它是中国诗歌里"月亮"和"美人"结伴登场的老祖先，后来李白写"床前明月光"、苏轼说"月下独酌"，都还受着这首小诗的影响呢！短短几句，没有一个"爱"字，却把相思写得清清楚楚。` }] },
  { id: 25, title: "汉广（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "南有乔木，不可休思，汉有游女，不可求思，汉之广矣，不可泳思",
    tags: "诗经,爱情",
    color: "#d97706",
    sections:[    { id: 1, title: "汉广（节选）", original: `南有乔木，不可休思。
汉有游女，不可求思。
汉之广矣，不可泳思。
江之永矣，不可方思。`, translation: `同学们，我们来读一读这首古老的诗篇《汉广》。它出自《诗经》，是三千多年前人们唱的歌。南方有棵高大的乔木，却不能走到它树荫下去休息；汉水边有一位游玩的姑娘，诗人心中十分爱慕，却没有办法去追求她。汉水呀，宽阔无边，想游也游不过去；长江呀，浩浩荡荡，想绕也绕不到对岸。这句写得好，诗人用宽广的江水，比喻自己心中那一份可望而不可及的思念，读来让人既感动又惆怅。`, interpretation: `这是三千年前一位年轻的樵夫唱的歌。那时候，江汉一带是楚国的地方，树木茂盛，汉水边常有出游的女子。小伙子远远看见一位美丽的姑娘，心里喜欢得不行，可就是够不着——树太高歇不了凉，水太宽游不过去，江太长绕不过去。他用“高高的树”“宽宽的江”来形容自己追不到心爱姑娘的愁苦，全诗翻来覆去念着“不可”“不可”，像在叹气。这种“求之不得”的心情，从古唱到今，后来人常说“可望而不可即”，就是这种滋味儿呢！` }] },
  { id: 26, title: "柏舟（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "泛彼柏舟，亦泛其流，耿耿不寐，如有隐忧，我心匪石，不可转也",
    tags: "诗经,感怀",
    color: "#d97706",
    sections:[    { id: 1, title: "柏舟（节选）", original: `泛彼柏舟，亦泛其流。
耿耿不寐，如有隐忧。
我心匪石，不可转也。
我心匪席，不可卷也。`, translation: `同学们，我们来读一读《柏舟》。这首诗出自《诗经》，是一位女子在深夜里诉说心中的忧愁。我们先看前两句：那只柏木做成的小船在水里轻轻地漂荡，随着河水一起缓缓向前流去。这句写得好，用漂荡的小船来比喻自己漂泊不定的心境。接下来两句：她躺在床上翻来覆去，怎么也睡不着，心里好像藏着深深的、说不出口的忧愁。“耿耿”就是形容心里不安、难以入睡的样子。再看后四句：我的心并不是一块石头，不能让别人想翻转就翻转；我的心也不是一张席子，不能让别人想卷起就卷起来。这位女子是在郑重地表明：我的志向坚定，谁也别想改变我！这几句语气十分坚决，展现了古人宁折不弯的品格。`, interpretation: `这首诗来自两千多年前的《诗经》，是一位女子在深夜写下的心声。那时候女子地位低微，常常受委屈却无处诉说。诗里的“柏舟”是用柏树木做的小船，象征着女子柔弱却坚定的品格。她反复说自己的心“不是石头，不是席子”，意思是自己有主见、有骨气，绝不会因为别人说什么就改变想法。这种倔强的语气，在那个年代特别勇敢，也特别让人心疼。后来“我心匪石，不可转也”成了千古名句，常被用来形容人要有坚定的信念和立场。整首诗语言质朴，情感却非常强烈，是中国最早的“女性宣言”呢！` }] },
  { id: 27, title: "伐檀（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "坎坎伐檀兮，置之河之干兮，不稼不穑胡取禾三百廛兮",
    tags: "诗经,讽刺",
    color: "#d97706",
    sections:[    { id: 1, title: "伐檀（节选）", original: `坎坎伐檀兮，置之河之干兮。
河水清且涟猗。
不稼不穑，胡取禾三百廛兮？
不狩不猎，胡瞻尔庭有县貆兮？
彼君子兮，不素餐兮！`, translation: `同学们，我们来读一读这首古老的诗篇《伐檀》。诗的开头描写了伐木工人在河边砍伐檀树的情景：他们一下一下地砍着檀木，发出“坎坎”的声响，把砍下的树干放在河岸边。接着，诗人望向河水，只见水面清清，泛起了层层波纹。这句写得好，用清波来反衬伐木者辛苦的劳作。接下来两句是诗人的质问：那些贵族既不耕种也不收割，凭什么拿走三百户农家的稻谷呢？既不去打猎，为什么庭院里却挂满了獾肉呢？最后诗人忍不住讽刺说：那些所谓的君子老爷，可不是白白吃闲饭的呀！原来，古代的奴隶和农民用这首诗来控诉剥削者，表达心中不平的怒火。`, interpretation: `这首诗出自《诗经·魏风》，大约写于2500多年前的春秋时期。那时候贵族压迫百姓，劳动者辛苦一年却吃不饱饭。
诗中有个特别聪明的写法——一边干活一边发牢骚：砍着檀树，看着清清的河水，再回头看看自己辛苦劳作却穷得叮当响，而那些不干活的人家里却挂满了猎物，堆满了粮食。这种对比多么强烈！
最后一句“彼君子兮，不素餐兮”是反话，意思是：那些所谓的'君子'啊，难道是白吃饭的吗？表面上像是尊敬，其实是在狠狠嘲笑。
这种“一面干活一面吐槽”的写法，后来成了中国古典诗歌的经典传统，屈原、杜甫、白居易都学过这一招呢！` }] },
  { id: 28, title: "硕鼠",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "硕鼠硕鼠，无食我黍，三岁贯女，莫我肯顾，逝将去女，适彼乐土",
    tags: "诗经,讽刺",
    color: "#d97706",
    sections:[    { id: 1, title: "硕鼠", original: `硕鼠硕鼠，无食我黍！
三岁贯女，莫我肯顾。
逝将去女，适彼乐土。
乐土乐土，爰得我所！`, translation: `同学们，我们来读一读《硕鼠》这首诗。它出自《诗经》，是古代劳动人民在沉重的赋税压迫下发出的呐喊。诗的大意是这样的：大田鼠啊大田鼠，请你不要再吃我种的黄米啦！这里的'硕鼠'其实是在比喻那些贪得无厌的统治者。'三岁贯女'是说多年来我辛苦地供养着你，可你却一点也不肯照顾我、怜悯我。于是诗人发誓：'逝将去女'，我一定要离开你，去寻找那理想的'乐土'，一个没有剥削、安乐美好的地方。最后两句'乐土乐土，爰得我所'写得好，表达了诗人对幸福生活的无限向往，也让我们感受到古代百姓对美好家园的渴求。`, interpretation: `这首诗出自2500多年前的《诗经》，那时候农民辛苦种粮食，却被贵族统治者层层剥削，心里又气又无奈。诗人把剥削者比作又肥又大的田鼠——偷吃粮食，胖嘟嘟的，却一点不顾主人的死活。'三岁贯女，莫我肯顾'特别有名，意思是养了你多年，你却翻脸不认人！全诗反复念着'乐土乐土'，就像孩子盼着有一天能逃到没有坏人的地方。读起来押韵上口，还带着一股不服气的小脾气，是中国最早的'逃跑歌'之一，后来'逝将去女'成了古人表达决绝的经典名句。` }] },
  { id: 29, title: "鹿鸣（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "呦呦鹿鸣，食野之苹，我有嘉宾，鼓瑟吹笙",
    tags: "诗经,宴饮",
    color: "#d97706",
    sections:[    { id: 1, title: "鹿鸣（节选）", original: `呦呦鹿鸣，食野之苹。
我有嘉宾，鼓瑟吹笙。`, translation: `在一片开阔的原野上，几只小鹿正安安静静地吃着地上的青草，它们一边嚼着嫩绿的草叶，一边发出「呦呦」的叫声，声音又轻又软，好像在开心地唱歌一样。听说我有尊贵的客人从远方来到家里拜访，我高兴极了，赶紧让人搬出琴瑟来弹奏，又吹起了响亮的笙，乐声叮叮咚咚地响个不停，到处都是热热闹闹的声音，主人和客人都在一起欢快地聚会。`, interpretation: `这首诗出自两千多年前，是周王宴请宾客时唱的歌曲。古人爱在打猎时模仿鹿叫，没想到一群鹿正在原野上悠闲地吃着野草，这个画面被诗人写进了诗里。最妙的就是"呦呦鹿鸣"这四个字，成了流传千古的名句。后来曹操的"呦呦鹿鸣，食野之蒿"，就是从这里学来的。弹琴吹笙迎接客人，可见古人多么热情好客！` }] },
  { id: 30, title: "相鼠",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "相鼠有皮，人而无仪，人而无仪，不死何为",
    tags: "诗经,讽刺",
    color: "#d97706",
    sections:[    { id: 1, title: "相鼠", original: `相鼠有皮，人而无仪。
人而无仪，不死何为！
相鼠有齿，人而无止。
人而无止，不死何俟！`, translation: `同学们，我们来读一读这首《相鼠》吧。这是一首先秦时代的古诗，古人看见老鼠都要拿来和人比一比，可见古人多么看重人的品行。诗的第一句说：瞧，那老鼠还有一张皮呢，可人要是没有堂堂正正的仪表，没有让人尊敬的礼节，那还活着干什么呀？第二句接着讲：瞧，老鼠还有牙齿呢，可人要是没有品德、没有操守，连羞耻之心都没有，那还等什么呢——不如早点结束自己的生命。整首诗用老鼠作对比，反反复复地告诉我们：做人一定要有礼仪、有品德、有底线。这句写得好，把对无耻之人的厌恶表达得淋漓尽致，真是又气又痛心啊。`, interpretation: `这首诗来自大约两千多年前的《诗经》，那时候贵族们常常举办典礼和宴会，有些当官的虽然穿着漂亮衣服，却做事没规矩、品德很糟糕。这首小诗就是专门骂那些虚伪之人的——你看，连老鼠都有皮有齿，你堂堂一个人，连最起码的礼仪廉耻都不要了吗？它最大的特色就是用最简单的话说出最重的责骂，三句一重复，像在指着鼻子质问对方。这种'直接开骂'的写法在《诗经》里特别少见，读起来痛快又解气，也让我们看到古人并不是只会客气，他们也会用犀利的诗表达愤怒。` }] },
  { id: 31, title: "七月（节选）",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "七月流火，九月授衣，春日载阳，有鸣仓庚",
    tags: "诗经,农事",
    color: "#d97706",
    sections:[    { id: 1, title: "七月（节选）", original: `七月流火，九月授衣。
春日载阳，有鸣仓庚。
女执懿筐，遵彼微行，爰求柔桑。
七月在野，八月在宇，九月在户，十月蟋蟀入我床下。`, translation: `七月大火星向西偏，天气转凉啦；九月就把冬衣来发放。春天太阳暖洋洋，黄莺儿叫得真响亮。姑娘们提着深竹筐，顺着小路走，去采那嫩嫩的桑叶。七月蟋蟀还在田野里，八月跳到屋檐下，九月躲到门里面，十月钻到我床底下啦。`, interpretation: `这首诗来自两千多年前的西周，是农民伯伯一边干活一边唱的歌。那时候没有日历表，人们抬头看天上的大火星来定季节。大火星一偏西，夏天就过去啦，该准备过冬的衣服了。诗里最有意思的是写蟋蟀搬家：七月在野地，八月到屋檐，九月进房门，十月钻床底——跟着天气变冷一步步往屋里跑，多可爱呀！这种把虫子当主角来写的法子特别生动，后来李白、杜甫都爱学这种'顺着季节讲故事'的写法呢。` }] },
  { id: 32, title: "绿衣",
    author: "佚名(诗经)",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "绿兮，衣兮",
    tags: "诗经,悼亡",
    color: "#d97706",
    sections:[    { id: 1, title: "绿衣", original: `绿兮衣兮，绿衣黄裹。
心之忧矣，曷维其已！
绿兮衣兮，绿衣黄裳。
心之忧矣，曷维其亡！
绿兮丝兮，女所治兮。
我思古人，俾无訧兮！
絺兮绤兮，凄其以风。
我思古人，实获我心！`, translation: `绿色的外衣啊，绿上衣配黄色衬里。看到它，我心里好难过，这悲伤什么时候才能停止啊！绿色的外衣啊，绿上衣配黄色下裙。看到它，我心里好难过，这思念什么时候才能忘怀啊！那绿色的丝线啊，全是你亲手纺出来的。我想起去世的妻子啊，她让我从没有过错！细麻布啊粗麻布啊，天冷了穿在身上多么凉啊。我想起去世的妻子啊，她最懂我的心思！`, interpretation: `这首诗出自《诗经·邶风》，大约是公元前500多年前的作品。相传是卫庄姜或一位贵族男子为悼念亡妻而作，充满了对已故爱人的深切思念。诗人触物伤情，看到妻子亲手缝制的绿色衣裳和丝线，便悲从中来——'绿衣黄裳'是衣物的颜色，'黄裹'是黄色的衬里，这些细致的描写说明他一直珍藏着亡妻的遗物。最动人的是'我思古人，实获我心'——世上再没有人像她那样懂我。这首诗开创了中国诗歌'悼亡'题材的先河，后世潘岳的《悼亡诗》、元稹的'曾经沧海难为水'、苏轼的'十年生死两茫茫'，都受到了这首小诗的影响。可以说，悼念亲人的深情，从三千年前就开始打动人心了。` }] },
  { id: 33, title: "哀郢（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "鸟飞反故乡兮狐死必首丘",
    tags: "楚辞,感怀",
    color: "#d97706",
    sections:[    { id: 1, title: "哀郢（节选）", original: `鸟飞反故乡兮，狐死必首丘。
信非吾罪而弃逐兮，何日夜而忘之！`, translation: `同学们，我们来读一读《哀郢》中的名句。鸟儿无论飞得多远，最终都要飞回自己的巢穴；狐狸在临死的时候，也一定会把头朝向它出生的小山。这句写得好啊，前一句说的是鸟，后一句说的是狐，连用两个动物的小故事，其实都在讲一个道理——动物尚且眷恋故土，更何况是人呢？接着诗人说：我真的没有犯下什么罪过，却被朝廷放逐，远远地离开了家乡郢都。字里行间满是委屈与思念，令人动容。`, interpretation: `这首诗写于战国末期，秦国大军攻占了楚国都城郢都，屈原被迫流亡，眼看家园沦丧，悲痛万分。诗中用鸟归巢、狐首丘两个动人故事，说明万物都眷恋故土，反衬出自己被迫离乡的哀伤。屈原通过奇特的想象和真挚的情感，让读者仿佛看见一位白发老人在江边独自垂泪。这种深沉的家国情怀，后来成为中国人心中爱国忧民的精神象征。` }] },
  { id: 34, title: "九辩（节选）",
    author: "宋玉",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "悲哉秋之为气也萧瑟兮草木摇落而变衰",
    tags: "楚辞,感怀",
    color: "#d97706",
    sections:[    { id: 1, title: "九辩（节选）", original: `悲哉秋之为气也！萧瑟兮，草木摇落而变衰。
憭栗兮，贫士失职而志不平。
廓落兮，羁旅而无友生。`, translation: `同学们，我们来读一读《九辩》中的这一节。秋天真让人伤心啊，到处是一片凄凉冷清的样子！草木在秋风中摇摆、凋零，变得枯萎衰败。“坎廪兮”写得好，这两个字形容一个人坎坷不得志的样子——可怜那些贫寒的读书人，他们失去了官职，心里满是委屈和不平。“廓落兮”是说他们觉得世界空旷又孤独，没有人理解自己。这段话表面上写秋天的悲凉，实际上是在借秋风抒发自己怀才不遇的感慨。`, interpretation: `这是战国时期楚国诗人宋玉写的《九辩》中的句子，开创了中国文学“悲秋”的传统。在那战乱纷争、仕途坎坷的年代，读书人常常怀才不遇，宋玉借秋天的萧瑟抒发自己内心的苦闷。诗中最妙的就是把“秋天”和“失意的读书人”连在一起——草木衰落就像人才被埋没，从此“悲秋”成了文人表达失意、孤独的经典方式，影响了杜甫、柳永等无数后辈诗人。` }] },
  { id: 35, title: "山鬼（节选）",
    author: "屈原",
    dynasty: "春秋战国",
    category: "春秋战国",
    summary: "若有人兮，山之阿被薜荔兮，带女萝既含睇兮",
    tags: "楚辞,神话",
    color: "#d97706",
    sections:[    { id: 1, title: "山鬼（节选）", original: `若有人兮，山之阿。
被薜荔兮，带女萝。
既含睇兮，又宜笑。
乘赤豹兮，从文狸。
辛夷车兮，结桂旗。
风飒飒兮，木萧萧。
思公子兮，徒离忧。`, translation: `好像有个人儿啊，住在山坳里，身披薜荔香草，腰系女萝长带。眼波流转含情脉脉，笑容温柔又美好。骑着红色的豹子，后面跟着花纹的野狸。辛夷做的花车，桂花枝扎成的彩旗。风吹过来，树叶沙沙响，她啊，心里想念着那位公子。`, interpretation: `这首《山鬼》出自战国时期楚国大诗人屈原的《九歌》，写的是一位住在深山里的女神——山鬼姑娘。屈原被流放后，吸收楚地民间祭歌的养分，写下了这些美丽的诗篇。诗中最有画面感的是山鬼的出行：赤豹拉车、文狸跟随、辛夷为车、桂枝为旗，想象多么奇特！山风吹过树梢沙沙作响，她却在痴痴等待心上人。这份等待中的孤独与深情，让两千多年后的我们读来仍然心动。它告诉我们：古人不只有严肃的道理，屈原笔下的神话世界也可以这样浪漫而温柔。` }] },
  { id: 36, title: "江南",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "江南可采莲，莲叶何田田，鱼戏莲叶间",
    tags: "汉,经典",
    color: "#dc2626",
    sections:[    { id: 1, title: "江南", original: `江南可采莲。
莲叶何田田！
鱼戏莲叶间。
鱼戏莲叶东，鱼戏莲叶西，
鱼戏莲叶南，鱼戏莲叶北。`, translation: `同学们，我们来读一首古老的汉乐府诗《江南》。江南，就是长江以南水乡一带的美丽地方。整首诗只有一句核心意思，却写得生动极了。

第一句“江南可采莲”，告诉我们江南真是个好地方，水塘里长满了莲蓬，到了夏天，人们可以划着小船去采莲子，多么惬意啊！

第二句“莲叶何田田”，这个“何”字要特别注意，它的意思是“多麼”，表示感叹。“田田”就是莲叶长得又密又绿、挨挨挤挤的样子，仿佛一片绿色的海洋。

第三句“鱼戏莲叶间”，写鱼儿在莲叶中间欢快地游来游去，嬉戏玩耍。

最后四句连着说“鱼戏莲叶东……鱼戏莲叶西……鱼戏莲叶南……鱼戏莲叶北”，诗人故意把“东、西、南、北”重复说了一遍，读起来朗朗上口，充满了活泼的节奏感。这句写得好，它让我们仿佛看见鱼儿忽东忽西、忽南忽北，自由穿梭在碧绿的莲叶之间，整个江南水乡都活了起来。

同学们，这首诗没有华丽的辞藻，只用简单的重复，就把江南采莲的欢乐情景展现得淋漓尽致，真是越读越有味道呢！`, interpretation: `这是一首汉代流传下来的采莲歌，歌词本该是“江南可采莲，莲叶何田田”，后面原是“鱼戏莲叶间”加上“东西南北”四个方向。但因为古人写书没有标点，抄来抄去就挤成了一团，变成了我们今天看到的样子。诗里描绘了江南水乡少女一边采莲、一边看鱼儿在莲叶间穿梭的欢乐情景，画面清新活泼。鱼儿在东南西北四处游动，仿佛在和采莲人捉迷藏，特别有趣味。这首汉乐府小诗语言明快、节奏感强，后人常把它当作儿歌来读，千年传唱不衰。` }] },
  { id: 37, title: "长歌行",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "少壮不努力，老大徒伤悲",
    tags: "汉,哲理",
    color: "#dc2626",
    sections:[    { id: 1, title: "长歌行", original: `青青园中葵，朝露待日晞。
阳春布德泽，万物生光辉。
常恐秋节至，焜黄华叶衰。
百川东到海，何时复西归？
少壮不努力，老大徒伤悲！`, translation: `绿油油的菜园里长着向日葵
清晨的露珠等着太阳来晒干
春天把阳光雨露洒向人间
世上的万物都焕发着光彩
常常担心秋天匆匆到来
叶子变黄、花儿凋零一片衰败
无数江河向东奔流入大海
什么时候才能再向西流回
人在年轻力壮时不发奋努力
到了年老体衰时只能空悲伤`, interpretation: `这首汉代乐府诗像一位慈祥的长辈在和你聊天。它先用葵菜沾露、春天生辉的美好画面让你沉浸其中，再突然话锋一转：秋天一来，叶子枯黄；江河东去，永不西归——时间就是这样一去不回头呀！最后两句是全诗最响亮的警钟，告诉我们：小时候不努力，长大只能后悔。这首诗最厉害的地方是用我们身边看得见、摸得着的事物来讲大道理，所以一千多年来，每当有人虚度光阴，大人们就会念起'少壮不努力，老大徒伤悲'这两句话。它还被写进无数学校的墙上，成了陪伴一代代孩子长大的'座右铭'呢！` }] },
  { id: 38, title: "观沧海",
    author: "曹操",
    dynasty: "汉",
    category: "汉",
    summary: "东临碣石，以观沧海，日月之行，若出其中，星汉灿烂，若出其里",
    tags: "汉,写景",
    color: "#dc2626",
    sections:[    { id: 1, title: "观沧海", original: `东临碣石，以观沧海。
水何澹澹，山岛竦峙。
树木丛生，百草丰茂。
秋风萧瑟，洪波涌起。
日月之行，若出其中；
星汉灿烂，若出其里。
幸甚至哉，歌以咏志。`, translation: `我向东爬上了碣石山，来欣赏大海的壮丽景色。海水波涛起伏，多么宽广。远处的小山和岛屿高高地矗立着。岛上树木茂盛，各种各样的草长得又密又旺。秋风吹来，发出沙沙的声音，巨大的海浪翻涌起来。太阳和月亮的运行，好像都是从这片大海里升起来的。灿烂的银河，也好像是从大海里流出来的。`, interpretation: `这首诗写于公元207年，曹操北征乌桓凯旋途中。登上碣石山，他被眼前的大海深深震撼，于是写下了这首气吞山河的诗。诗中“澹澹”的海水、“竦峙”的山岛、“丰茂”的百草，都是大自然的实景，但最妙的是最后四句——太阳、月亮、银河，都好像是从大海里升起，曹操用这种夸张的想象，把大海写得比天还大。这正是他胸中统一天下抱负的写照：一个能包容宇宙的人，才能成就大事业。这种以景抒怀的写法，后来被很多诗人学习，比如毛泽东的《浪淘沙·北戴河》就化用了“秋风萧瑟，洪波涌起”。` }] },
  { id: 39, title: "龟虽寿",
    author: "曹操",
    dynasty: "汉",
    category: "汉",
    summary: "老骥伏枥，志在千里，烈士暮年，壮心不已",
    tags: "汉,哲理",
    color: "#dc2626",
    sections:[    { id: 1, title: "龟虽寿", original: `神龟虽寿，犹有竟时。
腾蛇乘雾，终为土灰。
老骥伏枥，志在千里；
烈士暮年，壮心不已。
盈缩之期，不但在天；
养怡之福，可得永年。
幸甚至哉，歌以咏志。`, translation: `传说中的神龟虽然特别长寿，但终究也有死亡的一天。能够腾云驾雾的飞蛇，最终也会变成土和灰。千里马老了趴在马槽里，可它的志向仍然是驰骋千里。有抱负的人到了晚年，雄心壮志也丝毫不会减退。寿命的长短，不完全由老天爷决定。只要保养得好心情愉快，也能健康长寿活到一百岁。`, interpretation: `这是曹操五十三岁时写下的名篇《龟虽寿》。东汉末年天下大乱，他率军北征乌桓凯旋，豪情满怀之际写下这组诗，鼓励自己也要鼓励将士们不要服老。诗中最闪亮的意象就是"老骥伏枥，志在千里"——千里马老了趴在槽头，心里想的还是奔跑万里，多么有气势！这句诗也成为千古名句，激励着无数人不论年纪多大，都要保持一颗向前的心。这首诗最厉害的地方在于：前四句说神龟飞蛇都有尽头，似乎很悲观；后四句笔锋一转，说人的寿命靠自己来掌握，充满了昂扬向上的力量，让短短几十个字里既有哲理又有热血，特别适合少年人诵读记诵。` }] },
  { id: 40, title: "短歌行（节选）",
    author: "曹操",
    dynasty: "汉",
    category: "汉",
    summary: "对酒当歌，人生几何，青青子衿，悠悠我心，周公吐哺，天下归心",
    tags: "汉,抒情",
    color: "#dc2626",
    sections:[    { id: 1, title: "短歌行（节选）", original: `对酒当歌，人生几何？
譬如朝露，去日苦多。
慨当以慷，忧思难忘。
何以解忧？唯有杜康。
青青子衿，悠悠我心。
但为君故，沉吟至今。
呦呦鹿鸣，食野之苹。
我有嘉宾，鼓瑟吹笙。
明明如月，何时可掇？
忧从中来，不可断绝。
越陌度阡，枉用相存。
契阔谈䜩，心念旧恩。
月明星稀，乌鹊南飞。
绕树三匝，何枝可依？
山不厌高，海不厌深。
周公吐哺，天下归心。`, translation: `对着美酒就该放声高歌，人生能有多少好时光？就像早晨的露水，太阳一晒就没了，逝去的日子苦多乐少啊。心中激荡满腔不平，可愁绪却总也难忘。什么东西能消除烦恼？只有美酒杜康。穿青衣的读书人啊，我日夜把你们挂念。只因为你们的缘故，我低声吟唱直到今天。月色明亮，星星稀少，乌鸦和喜鹊向南飞去。山的胸怀不嫌高，海的度量不嫌深。周公热情接待贤才，天下人都甘心归顺。`, interpretation: `这首诗写于东汉末年，天下大乱，曹操雄心勃勃想要统一中国，却苦于身边人才不足。一边喝酒一边唱歌，表面上感叹人生短暂像朝露易干，其实是在抒发求贤若渴的焦急心情。他用“青青子衿”直接喊话读书人快来投奔我，又用“山不厌高，海不厌深”打比方——山再高也不嫌堆得更高，海再深也不嫌灌得更深，表示自己容人的气量有多大。最后搬出周公“一顿饭吃三次、吐出来接待贤人”的典故，意思是说：你们来了，我一定好好对待。短短几句，把一个政治家的豪情和心事写得明明白白，后来“对酒当歌”成了形容豪迈气概的常用语，流传了一千八百年。` }] },
  { id: 41, title: "蒿里行",
    author: "曹操",
    dynasty: "汉",
    category: "汉",
    summary: "白骨露于野，千里无鸡鸣，生民百遗一，念之断人肠",
    tags: "汉,战争",
    color: "#dc2626",
    sections:[    { id: 1, title: "蒿里行", original: `关东有义士，兴兵讨群凶。
初期会盟津，乃心在咸阳。
军合力不齐，势利使人争。
淮南弟称号，刻玺于北方。
铠甲生虮虱，万姓以死亡。
白骨露于野，千里无鸡鸣。
生民百遗一，念之断人肠。`, translation: `函谷关以东有各路起义军，他们起兵讨伐那些凶恶的乱臣贼子。可是各路军队聚集在一起，却不能齐心协力，因为权势和利益让人们互相争斗。将士们长期征战，身上的铠甲里都长出了虱子的幼虫（虮），老百姓大量死亡，尸骨遍野，千里之地听不到一声鸡叫。活下来的人一百个里只剩下一两个。想到这些惨状，真让人肝肠寸断。`, interpretation: `这首诗写于东汉末年，那是群雄并起、战乱不断的年代。曹操作为一位有抱负的政治家和诗人，眼睁睁看着各路兵马各怀私心、不肯协力，导致战火连天、生灵涂炭。诗中最震撼的意象就是'白骨露于野，千里无鸡鸣'——遍地白骨、千里荒寂，连鸡叫的声音都没有，画面感极强，让人读来心惊。'生民百遗一'更是以数字写尽人间惨剧。这种直面现实的写法，让这首诗被誉为'汉末实录'，也开创了后世杜甫'诗史'传统的先河。` }] },
  { id: 42, title: "白马篇（节选）",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "捐躯赴国难，视死忽如归",
    tags: "三国,经典",
    color: "#f97316",
    sections:[    { id: 1, title: "白马篇（节选）", original: `白马饰金羁，连翩西北驰。
弃身锋刃端，性命安可怀？
父母且不顾，何言子与妻？
捐躯赴国难，视死忽如归。`, translation: `同学们，我们来读一读这首《白马篇》。它出自三国时期曹植的笔下，描写的是一位骑着白马的少年英雄，勇敢奔赴战场、保卫国家的故事。下面我们一句一句来理解。第一句“骑着白马拉金笼头，飞奔着向西北方向去”，是说英雄骑着一匹雪白的战马，马头上戴着金色的笼头，骏马飞快地向西北边疆驰去。第二句“我既然投身在刀锋之间，哪里还顾得上自己的性命”，讲的是他既然已经站在刀剑的锋刃之上作战，就把自己的安危完全抛在脑后了。这句写得好，把英雄无所畏惧的气概一下子写了出来。第三四句“连父母都顾不上了，更别提我的儿子和妻子”，意思是战场危急，他连自己的父母都无法照顾，又怎么会去牵挂自己的儿女和妻子呢？最后两句“为国家献身去解救危难，把死亡看得像回家一样平常”，是全诗最感人的地方，说明他把报效国家当作最高的使命，把为国牺牲看成是光荣的归宿。这种英勇无私、视死如归的精神，正是这首诗流传千古的原因。`, interpretation: `这首诗写于三国时期，那时候群雄争霸，战争不断，年轻人纷纷投军报国。曹植用“白马”“金羁”勾勒出一位英俊少年英雄的形象，他骑着白马奔驰西北边塞，豪气冲天。诗中最动人的是“捐躯赴国难，视死忽如归”——为了国家，连死亡都像回家一样毫不在乎。这两句成为千古名句，激励了一代又一代的爱国志士。整首诗语言铿锵有力，对仗工整，读起来就像听到战鼓在响，特别有男子汉的豪情！` }] },
  { id: 43, title: "陌上桑（节选）",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "日出东南隅，照我秦氏楼，秦氏有好女，自名为罗敷",
    tags: "汉,叙事",
    color: "#dc2626",
    sections:[    { id: 1, title: "陌上桑（节选）", original: `日出东南隅，照我秦氏楼。
秦氏有好女，自名为罗敷。
行者见罗敷，下担捋髭须。
少年见罗敷，脱帽著帩头。
耕者忘其犁，锄者忘其锄。`, translation: `太阳从东南方升起来，阳光照在秦家的楼上。秦家有个美丽的姑娘，她的名字叫罗敷。过路的人看见了罗敷，放下担子捋着胡须。年轻人看见了罗敷，摘下帽子重新整理包头。耕地的人看见她，忘记了自己在犁地。锄地的人看见她，忘记了自己在锄地。`, interpretation: `这首《陌上桑》来自汉代，是一首讲故事的民歌。故事发生在日出东南的清晨，阳光照在秦家楼上，美丽的罗敷登场啦！作者没有直接写罗敷长得多漂亮，而是用了一个超厉害的写法——通过“行者”“少年”“耕者”“锄者”四种人的反应，从侧面烘托出罗敷的惊人美貌。这就是中国古诗里常说的“侧面描写”，比直接说“她真美”高明多啦！这首汉乐府后来还被改编成戏曲《秦香莲》的一部分，著名的诗句“行者见罗敷，下担捋髭须”传诵千年，成为了描写美人的经典名句。` }] },
  { id: 44, title: "十五从军征",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "十五从军征，八十始得归，羹饭一时熟，不知饴阿谁",
    tags: "汉,叙事",
    color: "#dc2626",
    sections:[    { id: 1, title: "十五从军征", original: `十五从军征，八十始得归。
道逢乡里人，家中有阿谁？
遥看是君家，松柏冢累累。
兔从狗窦入，雉从梁上飞。
中庭生旅谷，井上生旅葵。
烹谷持作饭，采葵持作羹。
羹饭一时熟，不知饴阿谁。
出门东向看，泪落沾我衣。`, translation: `十五岁就去当兵打仗，八十岁才终于回到家乡。路上遇到一个老乡，问：我家里还有什么人？老乡指着远处说：那是你的家，但已经是松树柏树掩映的坟墓了。一堆堆的坟头。野兔从狗洞钻进屋里，野鸡从房梁上扑棱飞起。院子里长着野生的谷子，井台边长着野生的葵菜。舀来煮成饭，一会儿就熟了，却不知道该给谁吃。走出门向东望去，泪水一串串落下，打湿了我的衣裳。`, interpretation: `这首汉代乐府诗写了一位少年从军、老来归家的老兵。背景是汉朝常年战乱，百姓被大量征召入伍，很多人一辈子都回不了家。诗中最震撼的意象是'松柏冢累累'——曾经的家变成了坟地，野兔从狗洞出入、野鸡在梁上飞，这些反常的细节让人感受到战乱年代的荒凉。诗最后'泪落沾我衣'，没有大哭大喊，只是一个老人默默流泪的样子，反而更让人心酸。这首诗用最简单的语言写出了最深的不幸，是古代战争诗中难得的写实杰作，后来杜甫的'无家问消息'等名句，都受到它的影响。` }] },
  { id: 45, title: "迢迢牵牛星",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "迢迢牵牛星，皎皎河汉女，盈盈一水间，脉脉不得语",
    tags: "汉,爱情",
    color: "#dc2626",
    sections:[    { id: 1, title: "迢迢牵牛星", original: `迢迢牵牛星，皎皎河汉女。
纤纤擢素手，札札弄机杼。
终日不成章，泣涕零如雨。
河汉清且浅，相去复几许？
盈盈一水间，脉脉不得语。`, translation: `那遥远又明亮的牵牛星啊，那皎洁美丽的织女。她伸出细长柔美的手，正在机杼上不停地织布。可是一整天也没织成一匹，眼泪像下雨一样落下来。那银河又清又浅，他们相隔能有多远呢？只隔着一条清澈的河流，却只能远远相望，谁也说不出话来。`, interpretation: `这首诗选自《古诗十九首》，大约诞生于东汉末年。那时候战乱频繁，人们常常离别，诗人借天上牛郎织女的故事，写出了人世间有情人不能相见的悲伤。诗里最动人的是"盈盈一水间，脉脉不得语"——明明只隔着一条清浅的河，却谁也不能开口说话，那种又近又远的感觉，是不是很像你和好朋友被分在不同班级时的想念？全诗十个叠字"迢迢、皎皎、纤纤、札札、盈盈、脉脉"连用，读起来像唱歌一样，是它最大的特色。后来"盈盈一水间，脉脉不得语"成了千古名句，连曹植、李白都学过这种写法呢！` }] },
  { id: 46, title: "行行重行行",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "行行重行行，与君生别离，相去万余里，各在天一涯",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "行行重行行", original: `行行重行行，与君生别离。
相去万余里，各在天一涯。
道路阻且长，会面安可知？
胡马依北风，越鸟巢南枝。
相去日已远，衣带日已缓。
浮云蔽白日，游子不顾反。
思君令人老，岁月忽已晚。
弃捐勿复道，努力加餐饭。`, translation: `走啊走啊不停地走，就这样和你活生生地分开。我们相隔万里远，各自在一个天涯。路又险又长，什么时候才能再见面？北方的马总依恋着北风，南方的鸟把窝筑在南边的树枝上。分开的日子越来越远，我的衣带一天比一天宽松。想念你让人渐渐老去，一年又一年匆匆过去，岁月已晚。不要再说被抛弃的话了，你只管好好吃饭保重身体。`, interpretation: `这首诗出自汉代《古诗十九首》，是思乡念友诗中的名篇。当时许多读书人为了做官离开家乡，常年在外漂泊，特别思念亲人朋友。诗中用北马南鸟的有趣比喻，说明万物都眷恋故土，何况人呢？最后那句"努力加餐饭"流传千古，明明是自己吃不下饭，却叮嘱对方保重，说不出的牵挂都藏在饭菜里。这首诗最大的特点就是不说大道理，全用家常话诉说真情，所以特别打动人心。` }] },
  { id: 47, title: "涉江采芙蓉",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "涉江采芙蓉，兰泽多芳草，采之欲遗谁，所思在远道",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "涉江采芙蓉", original: `涉江采芙蓉，长洲郁幽兰。
采之欲遗谁？所思在远道。
还顾望旧乡，长路漫浩浩。
同心而离居，忧伤以终老。`, translation: `我渡过江水去采摘荷花，兰花生长的地方长满了香草。我采了这些花想送给谁呢？我想念的人啊，在很远很远的地方。回头望一望家乡，漫漫长路无边无尽。我们明明是相爱的人，却要分开两地，只能带着这份忧伤，慢慢变老。`, interpretation: `这首诗出自《古诗十九首》，是东汉末年的作品。那时候社会动荡，很多人离开家乡去远方谋生，和亲人、爱人长久分离。诗里写一个人渡过江水去采荷花，想送给远方的心上人，可怎么都够不到，只能回头望着家乡叹气。最动人的是最后两句——明明是相爱的人，却被距离隔开，一辈子都在思念中度过。这种'想见却见不到'的心情，几百年来打动了一代又一代人，成了思念远方亲人时最常被想起的诗句。` }] },
  { id: 48, title: "明月何皎皎",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "明月何皎皎，照我罗床帏，忧愁不能寐，揽衣起徘徊",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "明月何皎皎", original: `明月何皎皎，照我罗床帏。
忧愁不能寐，揽衣起徘徊。
客行虽云乐，不如早旋归。
出户独彷徨，愁思当告谁？
引领还入房，泪下沾裳衣。`, translation: `明月多么明亮皎洁呀，清冷的光辉照进了我的罗帐床帏。我满心忧愁，怎么也睡不着，只好披上衣服起来在屋里走来走去。听说出门在外也许很快乐，可我总觉得，还不如早些回家乡。我走出门独自徘徊，满腹的愁苦又能讲给谁听？抬头望天久久出神，最终还是转身回到房里，伤心落下的泪水打湿了衣裳。`, interpretation: `这首诗出自汉代《古诗十九首》，是一位漂泊在外的游子在月夜写下的思念家乡之作。那时候很多人为了求学、做官或谋生，不得不背井离乡长年在外，想家是特别普遍的情感。诗中最打动人的意象就是那轮明月——它照进屋里，照出孤单，也照出游子无处安放的心。你看诗人多可爱，睡不着就起来溜达，出了门又不知该去哪儿，最后还是哭着回屋，把所有情绪都留给了月光。整首诗语言朴素，却写出了每个人都会有的"夜里想家"的体验，所以千百年来一直被人们传诵。` }] },
  { id: 49, title: "西北有高楼",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "西北有高楼，上与浮云齐，不惜歌者苦，但伤知音稀",
    tags: "汉,感怀",
    color: "#dc2626",
    sections:[    { id: 1, title: "西北有高楼", original: `西北有高楼，上与浮云齐。
交疏结绮窗，阿阁三重阶。
上有弦歌声，音响一何悲。
不惜歌者苦，但伤知音稀。
愿为双鸿鹄，奋翅起高飞。`, translation: `西边的天空中有一座高高的楼阁，它高高耸立，仿佛和天上飘浮的云朵一样高。楼上的窗户雕刻着精美的花纹，格子交错十分华丽。楼阁下面还有三层高高的台阶。楼上传来了弹琴唱歌的声音，这声音听起来多么悲伤啊！我并不是心疼唱歌人内心的苦楚，只是感慨这世上能听懂我心事的人实在太少了。真希望自己能变成一只展翅高飞的天鹅，和知音一起远走高飞。`, interpretation: `这首诗来自东汉，是《古诗十九首》中的一首，写于那个动荡不安的年代。许多读书人满腹才华却得不到赏识，心里非常苦闷。诗中有一座高高的楼阁，楼上传出悲伤的歌声，诗人路过听到，心里很有感触。"高楼""弦歌""鸿鹄"这几个意象特别美——高楼代表远大的理想，弦歌代表知音难觅，鸿鹄代表高远的志向。最打动人的是"不惜歌者苦，但伤知音稀"这两句，说出了千百年来人们的心声：真正懂你的人，比什么都珍贵。这种怀才不遇、渴望知己的情感，后来被无数诗人写过，比如俞伯牙摔琴谢知音的故事，就和这句诗的意思一模一样。` }] },
  { id: 50, title: "上邪",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "上邪我欲与君相，知长命无绝衰山，无陵江水为竭冬，雷震震夏雨雪天，地合乃敢与君绝",
    tags: "汉,爱情",
    color: "#dc2626",
    sections:[    { id: 1, title: "上邪", original: `上邪！
我欲与君相知，长命无绝衰。
山无陵，江水为竭，
冬雷震震，夏雨雪，
天地合，乃敢与君绝！`, translation: `同学们，我们来读一读这首汉代的乐府情歌《上邪》。这是一个女子对着天地发誓，向心上人说：天啊！我想和您相知相爱，这颗心呀，除非生命终结，否则永远都不会断绝。您听，她一口气举出了五种不可能发生的事情：除非高山变成平地，江水干涸见底；除非冬天雷声轰隆隆地响起来，夏日里飘起大雪；除非天和地合并在一起——只有到了那个时候，我才敢和您分开呀。这句写得好！她没有说“我不会离开您”，而是用一连串永远不会发生的奇迹，来证明自己的爱比天地还要长久，真是又热烈又动人。`, interpretation: `这首诗来自汉代，是一位女子对爱情发出的惊天誓言。那时的女子不善于表达情感，但诗中的她却如此勇敢热烈。诗人连用五种不可能发生的自然现象——山崩、江枯、冬雷、夏雪、天地合一，来反衬自己对爱情的忠贞。写法上想象大胆、排山倒海，气势震撼。这几句誓言成为千古名句，至今读来仍让人心头滚烫。` }] },
  { id: 51, title: "大风歌",
    author: "刘邦",
    dynasty: "汉",
    category: "汉",
    summary: "大风起兮云飞扬，威加海内兮归故乡，安得猛士兮守四方",
    tags: "汉,经典",
    color: "#dc2626",
    sections:[    { id: 1, title: "大风歌", original: `大风起兮云飞扬。
威加海内兮归故乡。
安得猛士兮守四方！`, translation: `同学们好，我们今天来读一读汉朝开国皇帝刘邦写的一首诗，名字叫《大风歌》。当时他刚刚战胜了项羽，统一了天下，回到家乡沛县，心里非常感慨，就写下了这首诗。我们来一句一句地看：第一句，“大风起兮云飞扬”，意思是：风呼呼地刮起来了，云朵在天空里到处飘荡。这一句写得好啊，把天地间那种气势磅礴的样子一下子就写出来了。第二句，“威加海内兮归故乡”，意思是：我的威名传遍了全国，今天终于可以风风光光地回到老家了。“海内”就是天下的意思。第三句，“安得猛士兮守四方”，意思是：怎样才能找到勇敢的将士，替我守住这辽阔的疆土呢？这句写出了刘邦在得意之中，又担心国家未来的心情。整首诗只有短短三句，却既有英雄的豪气，又有帝王的忧虑，是非常了不起的作品。`, interpretation: `这是汉高祖刘邦平定天下后，回到故乡沛县时所作。公元前196年，他战胜项羽建立汉朝，衣锦还乡，召集旧日好友饮酒庆祝。诗中短短三句，却藏着三层心情：起首一句气势磅礴，大风与飞云象征天下动荡；第二句难掩得意，'威加海内'写出他统一四海的豪情；第三句笔锋一转，从喜悦落入忧思——打天下容易，守天下难啊，他渴望有勇士帮他镇守辽阔的疆土。这首诗最妙的地方在于'得意不忘忧'，一个开国皇帝既有英雄气概，又有深谋远虑。后人常引用'威加海内'来形容功成名就，而'安得猛士兮守四方'也成为求贤若渴的千古名句。` }] },
  { id: 52, title: "垓下歌",
    author: "项羽",
    dynasty: "汉",
    category: "汉",
    summary: "力拔山兮，气盖世时不利兮，骓不逝虞兮，虞兮",
    tags: "汉,经典",
    color: "#dc2626",
    sections:[    { id: 1, title: "垓下歌", original: `力拔山兮气盖世。
时不利兮骓不逝。
骓不逝兮可奈何？
虞兮虞兮奈若何！`, translation: `同学们，我们来读一读这首《垓下歌》。这是两千多年前，西楚霸王项羽在兵败被围时唱的一首悲歌，充满了英雄末路的感慨。请大家跟着老师一句一句来理解。第一句“力拔山兮气盖世”，是说项羽自称力气大得能拔起大山，英雄气概盖过了世上所有的人。第二句“时不利兮骓不逝”，讲的是虽然自己无比英勇，可时运不济，连他最心爱的乌骓宝马也跑不动了。这句写得好，一个“逝”字就把战马疲惫、无法突围的样子写了出来。第三句“骓不逝兮可奈何”，是诗人对坐骑的叹息——宝马跑不了，我又有什么办法呢？最后一句“虞兮虞兮奈若何”，项羽连声呼唤爱妃虞姬的名字，表达了对她的牵挂与不舍。整首诗让我们感受到一位盖世英雄在绝境中的悲壮与深情。`, interpretation: `这是两千多年前西楚霸王项羽在乌江边自刎前唱的歌。当时项羽被刘邦的军队团团围住，四面传来楚国的歌声，他知道自己已经走投无路了。这首诗短短几句，却让人看到一个英雄的无奈与柔情——既有拔山盖世的霸气，也有对爱马和爱人虞姬的深深牵挂。特别是'虞兮虞兮奈若何'这一句，千百年来读起来都让人心酸难过。项羽虽然最后失败了，但他这份真性情，反而让他成了中国人心中最让人同情的英雄之一。` }] },
  { id: 53, title: "白头吟",
    author: "卓文君",
    dynasty: "汉",
    category: "汉",
    summary: "皑如山上雪，皎若云间月，愿得一心人，白头不相离",
    tags: "汉,爱情",
    color: "#dc2626",
    sections:[    { id: 1, title: "白头吟", original: `皑如山上雪，皎若云间月。
闻君有两意，故来相决绝。
今日斗酒会，明旦沟水头。
躞蹀御沟上，沟水东西流。
凄凄复凄凄，嫁娶不须啼。
愿得一心人，白头不相离。
竹竿何袅袅，鱼尾何簁簁。
男儿重意气，何用钱刀为！`, translation: `同学们，我们来读一读这首《白头吟》。它是一位女子对负心之人说的话。你听——爱情应当像山顶上覆盖的雪一样洁白无瑕，又像云层中悬挂的月亮一样明亮清澈。这句写得好，用雪和月来比喻真心，既纯洁又坚定。可听说你如今怀有二心，所以我特意来与你一刀两断，从此恩断义绝。最后两句是千古传诵的名句：我只盼着能找到一个对我全心全意的人，相伴相守，一直到头发白了也绝不分离。短短几句，把对真情的渴望和对变心的决绝都写了出来，让人读了既感动又敬佩。`, interpretation: `这首诗出自汉代才女卓文君之手，背景是她与才子司马相如的爱情故事——相如飞黄腾达后竟想另娶新欢，文君得知后悲愤交加，写下此诗。诗中最动人的是「皑如山上雪，皎若云间月」，用雪和月来比喻爱情的纯净美好，特别有画面感。而「愿得一心人，白头不相离」更是千古名句，道出了所有人对真爱的向往。文君没有哭哭啼啼，而是选择潇洒转身，这份骨气令人钦佩，也让她成为古代女性追求平等爱情的象征。` }] },
  { id: 54, title: "东门行",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "出东门不顾归盎中无斗米储架上无悬衣",
    tags: "汉,叙事",
    color: "#dc2626",
    sections:[    { id: 1, title: "东门行", original: `出东门，不顾归。
来入门，怅欲悲。
盎中无斗米储，还视架上无悬衣。
拔剑东门去，舍中儿母牵衣啼。
他家但愿富贵来，贱妾与君共哺糜。`, translation: `走出东门头也不回，
回到家中心里愁闷好后悔。
想要悲伤的是：米缸里没有一斗米的存粮。
回头看看衣架上，也没有一件可以穿的衣服。
一狠心，拔剑冲出东门去。
家里的小娃娃抱住他的衣服哭着不让走。
孩子说：我只盼着咱们家能富贵起来，
就算贫贱，也愿意和爸爸你一起喝稀粥过日子呀！`, interpretation: `这首汉代乐府诗来自两千多年前，没有留下作者的名字。它讲的是一位走投无路的父亲，因为家里揭不开锅、衣架上没有衣裳，被迫出门去做强盗。可刚迈出家门，小儿子就扯着他的衣角哭喊：就算穷得喝稀粥，也愿和爸爸在一起！短短几句话，写尽了汉代底层百姓的辛酸。诗中最动人的就是孩子那句"贱妾与君共哺糜"——穷，却有真情。这首《东门行》被后世称为"汉乐府第一佳作"，因为它不加修饰，像生活本身一样真实有力。` }] },
  { id: 55, title: "桃花源记（节选）",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "忽逢桃花林夹岸数百步中无杂树芳草鲜美落英缤纷",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "桃花源记（节选）", original: `晋太元中，武陵人捕鱼为业。
缘溪行，忘路之远近。
忽逢桃花林，夹岸数百步，中无杂树，芳草鲜美，落英缤纷。
土地平旷，屋舍俨然，有良田、美池、桑竹之属。
阡陌交通，鸡犬相闻。`, translation: `东晋太元年间，有个武陵人靠打鱼为生。他沿着溪水划船前行，忘记走了多远。忽然遇到一片桃花林，溪水两岸几百步都是桃树，中间没有别的树。芬芳的青草鲜嫩美丽，落下的花瓣纷纷扬扬。土地平坦开阔，房屋整整齐齐，还有肥沃的田地、美丽的池塘和桑树竹林这类景物。田间小路纵横交错，村子里能听见鸡叫狗叫的声音。`, interpretation: `东晋时期战乱频繁，百姓生活困苦，陶渊明就写下了这篇美丽的桃花源故事。这段话描述了渔人意外发现世外桃源的过程，"桃花林"是他心中理想世界的入口，落英缤纷的景象美得像一场梦。陶渊明用白描手法，不加修饰地铺陈出一幅安宁祥和的田园画面，让人读了心里也觉得平静舒服。"阡陌交通，鸡犬相闻"成了千古名句，后来很多人用"世外桃源"来形容那些远离烦恼的美好地方。` }] },
  { id: 56, title: "归园田居·其一",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "少无适俗韵，性本爱丘山，误落尘网中，一去三十年，久在樊笼里，复得返自然",
    tags: "魏晋南北朝,田园",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "归园田居·其一", original: `少无适俗韵，性本爱丘山。
误落尘网中，一去三十年。
羁鸟恋旧林，池鱼思故渊。
开荒南野际，守拙归园田。
方宅十余亩，草屋八九间。
榆柳荫后檐，桃李罗堂前。
暧暧远人村，依依墟里烟。
狗吠深巷中，鸡鸣桑树颠。
久在樊笼里，复得返自然。`, translation: `我从小就没有适应世俗的性格，天生就热爱山川田园。谁知不小心掉进了那张烦人的官场大网里，一晃就困了整整十三年。我就像被关住的鸟想念老树林，池塘里的鱼思念原来的深潭。如今终于回到家乡，在南边的田野开荒种地，守护自己笨拙的本分，回到这可爱的田园。房子四周有十来亩地，茅屋有八九间。榆树和柳树遮住后屋檐，桃树和李树排列在堂屋前。远处的村庄隐隐约约，缕缕炊烟轻轻飘散。深巷里传来狗叫声，桑树顶上有公鸡在叫喊。我就像被关在笼子里太久，今天终于又能回到大自然身边。`, interpretation: `东晋末年，官场黑暗腐败，陶渊明做了十三年小官后终于辞职回家。这首诗就像他给自然写的一封情书，核心意象是'樊笼'和'自然'的对立——官场是牢笼，田园才是家。他用最朴素的句子写出了最美的乡村画面：榆柳桃李、鸡鸣狗吠、远村炊烟，几乎成了中国田园诗的标准画面。后人一提'田园'就会想到陶渊明，他也被称为'古今隐逸诗人之宗'，意思是写归隐生活，他可是老祖宗级别的！` }] },
  { id: 57, title: "饮酒·其五",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "采菊东篱下，悠然见南山，此中有真意，欲辨已忘言",
    tags: "魏晋南北朝,田园",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "饮酒·其五", original: `结庐在人境，而无车马喧。
问君何能尔，心远地自偏。
采菊东篱下，悠然见南山。
山气日夕佳，飞鸟相与还。
此中有真意，欲辨已忘言。`, translation: `我家盖房子就在人群聚居的地方，可是却没有车马的喧闹声。你要问我怎么能做到这样？只因心境清远，觉得所住的地方自然就偏僻安静了。在东边的篱笆墙下采摘菊花，一抬头，悠然自得地望见了南山。傍晚山间的云雾缭绕，景色十分美好，飞鸟也成群结伴地飞回山去。这中间蕴含着人生的真谛，想要辩说清楚，却忘了该用怎样的言语来表达。`, interpretation: `东晋末年官场黑暗，陶渊明不愿为五斗米折腰，辞官归隐，这首诗就写于他隐居田园之后。诗中最经典的意象是"采菊东篱下，悠然见南山"——菊花象征高洁，南山代表自然的宁静，诗人随手摘菊，无意间抬头望见青山，悠然二字写尽了自在与洒脱。陶渊明是中国田园诗的鼻祖，这首诗以平淡的语言写出深远的意境，告诉小朋友们：真正的快乐不在热闹的远方，而在一颗安静下来的心里。` }] },
  { id: 58, title: "木兰诗",
    author: "佚名",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "万里赴戎，机关山度，若飞将军，百战死壮，士十年归，同行十二，年不知木，兰是女郎",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "木兰诗", original: `唧唧复唧唧，木兰当户织。
不闻机杼声，唯闻女叹息。
问女何所思，问女何所忆。
女亦无所思，女亦无所忆。
昨夜见军帖，可汗大点兵。
军书十二卷，卷卷有爷名。
阿爷无大儿，木兰无长兄。
愿为市鞍马，从此替爷征。
万里赴戎机，关山度若飞。
朔气传金柝，寒光照铁衣。
将军百战死，壮士十年归。
归来见天子，天子坐明堂。
策勋十二转，赏赐百千强。
可汗问所欲，木兰不用尚书郎。
愿驰千里足，送儿还故乡。
爷娘闻女来，出郭相扶将。
阿姊闻妹来，当户理红妆。
小弟闻姊来，磨刀霍霍向猪羊。
开我东阁门，坐我西阁床。
脱我战时袍，著我旧时裳。
当窗理云鬓，对镜帖花黄。
出门看火伴，火伴皆惊惶。
同行十二年，不知木兰是女郎。`, translation: `唧唧又唧唧，木兰对着门在织布。听不到织机的声音，只听见姑娘在叹息。一遍又一遍叹息的是谁家的姑娘？木兰姑娘。

听不见木兰织布的声音，只听见她一声声叹息。

她愿去集市买来骏马和马鞍，从此代替父亲去出征。

到各处关口山岭行军如飞，北方的寒气传来打更声，冰冷的月光照着铁甲战衣。

将军身经百战有的战死沙场，壮士们十年后才得胜归来。

回到家乡，打开我东厢房的门，坐上我西厢房的床，脱下我打仗时的战袍，换上我旧日的姑娘衣裳。

战友同行十二年，竟不知木兰原是位女郎！`, interpretation: `《木兰诗》是北朝民歌，大约流传于一千五百年前。诗里讲了一个叫花木兰的女孩，女扮男装，替年迈的父亲从军打仗，立下功劳后回乡，才发现她其实是女儿身。

全诗最有趣的是两个"对比"：一是战场上英勇杀敌的"将军"，和回家后梳妆打扮的"姑娘"是同一个人；二是十二年的战友朝夕相处，居然"不知木兰是女郎"，让人忍不住笑出声来。

诗歌语言明快活泼，读起来像唱歌一样顺口。"万里赴戎机，关山度若飞"写出行军迅速，豪气十足；"开我东阁门，坐我西阁床"又回到家中，语气轻快。

木兰的故事传到今天，谁都知道"巾帼不让须眉"。她勇敢、孝顺、又机灵，是中国孩子最喜爱的古代女英雄之一呢！` }] },
  { id: 59, title: "拟行路难·其六（节选）",
    author: "鲍照",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "对案不能食拔剑击柱长叹息自古圣贤尽贫贱何况我辈孤且直",
    tags: "魏晋南北朝,感怀",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "拟行路难·其六（节选）", original: `对案不能食，拔剑击柱长叹息。
丈夫生世会几时，安能蹀躞垂羽翼。
自古圣贤尽贫贱，何况我辈孤且直。`, translation: `对着饭菜却吃不下去，
拔出宝剑砍着柱子，满心愁苦。
叹息啊，大丈夫活在这世上，
什么时候才能有太平的时候？
就算像鸟儿一样垂下翅膀、迈着小步走，
自从古时候的圣贤以来，
都免不了贫穷和低贱，
何况我们这些又孤单又正直的人呢！`, interpretation: `这首诗写于南北朝那个乱糟糟的年代，鲍照家里穷，人又耿直，在官场里总被人排挤，心里憋了一肚子委屈。诗里最有意思的动作是“拔剑击柱”——想想看，一个书生气得拔剑去砍家里的柱子，那画面又急又无奈，真是太有感染力了！“蹀躞垂羽”说的是鸟儿收起翅膀、小心走路的样子，连圣贤都躲不过穷的命运，何况他这样性格直的人呢？这种“我穷我直我骄傲”的气魄，后来成了很多正直文人的心声，读起来特别痛快！` }] },
  { id: 60, title: "晚登三山还望京邑（节选）",
    author: "谢朓",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "余霞散成绮，澄江静如练",
    tags: "魏晋南北朝,写景",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "晚登三山还望京邑（节选）", original: `灞涘望长安，河阳视京县。
白日丽飞甍，参差皆可见。
余霞散成绮，澄江静如练。
喧鸟覆春洲，杂英满芳甸。`, translation: `我就像当年在灞水边遥望长安的王粲，又像在河阳远眺京城的潘岳。京城的屋檐在阳光下闪着光，高高低低的房屋都能看得清楚。天边的晚霞散开，像一匹匹彩绸；清澈的江水静静地流淌，像一条白绢。喧闹的鸟儿飞满了春日的小洲，各种鲜花开遍了芬芳的田野。`, interpretation: `这是南朝诗人谢朓登上三山眺望京城建康时写的。谢朓是著名的山水诗人，这几句是他眺望所见的美景。他用两个历史人物（王粲、潘岳）远望京城的典故开头，立刻让人感受到他对京城的依恋。接着连用四个比喻：屋檐如飞、晚霞像彩绸、江水像白绢，把眼前景色写得绚丽又宁静。后世李白那句“余霞散成绮，澄江静如练”几乎原封不动地化用了这里，可见谢朓写景多么精妙，影响有多大！` }] },
  { id: 61, title: "七哀诗（节选）",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "君若清路尘，妾若浊水泥，浮沉各异势，会合何时谐",
    tags: "三国,情感",
    color: "#f97316",
    sections:[    { id: 1, title: "七哀诗（节选）", original: `明月照高楼，流光正徘徊。
上有愁思妇，悲叹有余哀。
君若清路尘，妾若浊水泥。
浮沉各异势，会合何时谐。
愿为西南风，长逝入君怀。`, translation: `明亮的月光照在高高的楼上，月光来回地流动着。楼上有个满心忧愁的妇人，一声声悲叹，满怀哀伤。夫君就像路上飞扬的清尘，妾身就像水里沉下的浊泥。尘土飞扬、泥水下沉，各有各的去向，什么时候才能再相会呢？我真愿化作一阵西南风，一直吹进夫君的怀抱里。`, interpretation: `这首诗写于三国乱世，曹植被哥哥曹丕猜忌，屡遭迫害，诗中那位"愁思妇"正是他自己的影子。明月高楼的清冷景象，象征着孤独与思念；"清尘"和"浊水泥"用得很妙——一个轻扬天上，一个沉落水里，明明是同一种东西，却因为处境不同再也到不了一起。最后他宁愿化作一阵风扑进亲人怀抱，多么让人心疼！这首诗最早用"明月"写愁思，对后来曹雪芹写《葬花吟》都产生了影响呢。` }] },
  { id: 62, title: "咏荆轲（节选）",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "其人虽已没，千载有余情",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "咏荆轲（节选）", original: `燕丹善养士，志在报强嬴。
君子死知己，提剑出燕京。
雄发指危冠，猛气冲长缨。
登车何时顾，飞盖入秦庭。
其人虽已没，千载有余情。`, translation: `燕太子丹喜欢收养有才能的人，心里想着要向强大的秦国报仇。君子愿意为知己的朋友去死，荆轲提起了宝剑就离开了燕国京城。他气得头发直竖，把高高的帽子都快顶飞了，猛烈的豪气简直要把帽带都冲断。登上车子，他什么时候回头看过呢？驾着飞快的马车直向秦国的朝廷冲去。这个人虽然已经死去了，但过了千百年，他的豪情壮志依然让人感动。`, interpretation: `这首诗写于东晋时期，陶渊明平日里像个温柔的田园诗人，但他心里其实藏着对英雄的敬佩。秦国灭了六国，燕国太子丹为了报仇，派出勇士荆轲去刺杀秦王，结果失败了，荆轲也牺牲了。陶渊明最厉害的地方，是用"雄发指危冠，猛气冲长缨"这两句，把荆轲出发前那种又愤怒又悲壮的英雄气概写得活灵活现，好像你都能看见他气得头发炸起来的样子。这首诗让荆轲的故事流传得更广，连陶渊明这样不爱打打杀杀的诗人，都忍不住为他写诗点赞，可见真正的英雄精神是不分时代的！` }] },
  { id: 63, title: "五柳先生传（节选）",
    author: "陶渊明",
    dynasty: "魏晋南北朝",
    category: "魏晋南北朝",
    summary: "好读书不，求甚解每，有会意便，欣然忘食",
    tags: "魏晋南北朝,经典",
    color: "#8b5cf6",
    sections:[    { id: 1, title: "五柳先生传（节选）", original: `先生不知何许人也，宅边有五柳树，因以为号焉。
闲静少言，不慕荣利。
好读书，不求甚解；每有会意，便欣然忘食。
短褐穿结，箪瓢屡空，晏如也。`, translation: `五柳先生不知道是哪里的人。房屋旁边有五棵柳树，就用它做了自己的号。他性格安静，不爱说话，不羡慕荣华富贵。喜欢读书，不追求把每个字都弄懂；每当对书中的意思有所领会，就高兴得忘了吃饭。粗布短衣上打着补丁，饭篮和瓢里经常是空的，他依然安然自在。`, interpretation: `这是东晋大诗人陶渊明写的小传记，介绍了他想象中的自己——一位住在五棵柳树旁的先生。东晋时期官场黑暗，许多文人不愿同流合污，纷纷归隐田园。陶渊明借五柳先生，表达了自己安贫乐道、淡泊名利的志趣。文中"闲静少言，不慕荣利"是他最鲜明的形象，"好读书，不求甚解"更成为一种洒脱的阅读境界。短短几句，一位清贫却快乐的高人跃然纸上，影响了中国一千多年来读书人的精神追求。` }] },
  { id: 64, title: "野田黄雀行",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "高树多悲风，海水扬其波，利剑不在掌，结交何须多",
    tags: "三国,感怀",
    color: "#f97316",
    sections:[    { id: 1, title: "野田黄雀行", original: `高树多悲风，海水扬其波。
利剑不在掌，结交何须多。
不见篱间雀，见鹞自投罗。
罗家得雀喜，少年见雀悲。
拔剑捎罗网，黄雀得飞飞。`, translation: `高高的树梢上，悲凉的风呼呼地吹过。
海水翻涌着，卷起了层层波浪。
手中没有锋利的宝剑，
交朋友又何必太多？
你看那篱笆间的小雀，
正被鹞鹰追着，一头扎进了罗网。
设罗网的人逮到小雀真开心，
可少年看见了却心里发慌。
他拔出手中的剑，砍向那罗网，
黄雀挣脱出来，扑棱棱地飞向远方。`, interpretation: `这首诗写于三国时期，曹植的哥哥曹丕当上了皇帝，对他处处猜忌打压，他觉得有才能却没地方施展，就像被人关在笼子里一样憋屈。所以诗里的"利剑不在掌"其实是在说他自己——空有一身本事，却没人让他发挥。整首诗用"少年救雀"的小故事来打比方，讲的就是有本事的人应该去帮助那些遇到困难的人。曹植这种想冲破束缚、帮助弱者的心情，让这首诗读起来特别动人。后来"拔剑捎罗网"还成了名句，人们用它来形容路见不平、拔刀相助的勇敢。` }] },
  { id: 65, title: "赠从弟",
    author: "刘桢",
    dynasty: "三国",
    category: "三国",
    summary: "亭亭山上松，瑟瑟谷中风，风声一何盛，松枝一何劲",
    tags: "三国,咏物",
    color: "#f97316",
    sections:[    { id: 1, title: "赠从弟", original: `亭亭山上松，瑟瑟谷中风。
风声一何盛，松枝一何劲。
冰霜正惨凄，终岁常端正。
岂不罹凝寒，松柏有本性。`, translation: `高高的山上长着一棵挺拔的松树，山谷里吹来阵阵瑟瑟的寒风。风声是多么的猛烈啊，松树的枝干却是多么的刚劲！冰霜袭来，四周一片凄惨，但松树一年到头都保持着端端正正的姿态。难道松树不怕遭遇严寒吗？不是的，这是松柏天生就有的本性啊。`, interpretation: `这首诗是东汉末年刘桢写给堂弟的。当时社会动荡，许多人为了保命失去了气节，诗人便借松树来勉励堂弟要坚守品格。诗中最核心的意象就是"松柏"——它们不畏风霜、端正挺立，正是坚强不屈精神的象征。全诗以"松"和"风""冰霜"对比，一刚一柔，一烈一坚，写得刚健有力，朗朗上口。这种"托物言志"的手法后来被许多诗人沿用，比如陶渊明写菊、于谦写石灰，都受到了它的启发。` }] },
  { id: 66, title: "燕歌行",
    author: "曹丕",
    dynasty: "三国",
    category: "三国",
    summary: "秋风萧瑟天气凉，草木摇落露为霜，群燕辞归鹄南翔",
    tags: "三国,情感",
    color: "#f97316",
    sections:[    { id: 1, title: "燕歌行", original: `秋风萧瑟天气凉，草木摇落露为霜。
群燕辞归鹄南翔，贱妾茕茕守空房。
忧来思君不敢忘，不觉泪下沾衣裳。`, translation: `秋风阵阵吹来，天气越来越凉，树木花草枯黄凋零，露水也变成了白霜。一群群燕子和大雁都飞回南方去了。只有我孤零零地守在空荡荡的房间里。想念你的忧愁涌上心头，我怎么也不敢忘。不知不觉，眼泪就流了下来，打湿了衣裳。`, interpretation: `这是曹丕写给远方丈夫的思念之诗，背景是战乱年代，许多夫妻被迫分离。诗中用了秋风、霜冻、归燕这些秋天特有的景象，暗示时间流逝和别人的团聚，反衬出女主人公的孤独。最妙的是“群燕辞归”和“茕茕守空房”的对比，热闹是别人的，她只剩自己。曹丕把女子悄悄落泪写得又美又让人心疼，是后世思妇诗的典范，连“贱妾茕茕守空房”都成了名句。` }] },
  { id: 67, title: "七步诗",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "煮豆燃豆萁，豆在釜中泣，本是同根生，相煎何太急",
    tags: "三国,经典",
    color: "#f97316",
    sections:[    { id: 1, title: "七步诗", original: `煮豆燃豆萁，豆在釜中泣。
本是同根生，相煎何太急。`, translation: `把豆子煮熟，要用豆秸来点火燃烧——你看，锅底下烧着的，正是豆子自己的茎梗啊！锅里那些豆子被滚烫的水煮着，仿佛在伤心地哭泣：燃烧我们的柴火和我们要煮的东西，本来都是从同一条根上长出来的亲兄弟呀，为什么非要这样急急忙忙地、谁逼谁呢？这几句诗用一个烧豆煮饭的小小的厨房场景，说出了一个让人心里发酸的道理：兄弟之间，本是血脉相连的一家人，怎么能忍心这样彼此伤害呢？`, interpretation: `这首诗写于三国时期，相传曹植的哥哥曹丕当了皇帝后，忌惮弟弟的才华，命他七步之内作诗，否则就要处死他。曹植便吟出了这首诗。诗中用'豆萁'比喻曹丕，用'豆'比喻自己，'同根生'点明兄弟手足之情，控诉了哥哥对自己的迫害。整首诗用比喻的手法，把兄弟相残比作豆秸煮豆，形象又凄凉，最后一句'相煎何太急'流传千古，成为描写骨肉相残的经典名句。这首诗也让我们明白，家人之间应该相亲相爱，不要互相伤害。` }] },
  { id: 68, title: "白马篇",
    author: "曹植",
    dynasty: "三国",
    category: "三国",
    summary: "捐躯赴国难，视死忽如归",
    tags: "三国,经典",
    color: "#f97316",
    sections:[    { id: 1, title: "白马篇", original: `白马饰金羁，连翩西北驰。
弃身锋刃端，性命安可怀。
父母且不顾，何言子与妻。
名编壮士籍，不得中顾私。
捐躯赴国难，视死忽如归。`, translation: `同学们好，我们来读一读《白马篇》。这首诗出自曹植笔下，是一首歌颂英雄报国情怀的作品。请大家跟着老师一起逐句理解：骑着雪白的高头大马，配上金光闪闪的马笼头，跨上马背，向着西北方向飞奔而去。诗人接着写道：宁可把自己的身躯抛向刀剑的锋刃之下，又怎么能够贪恋个人的性命呢？为了解救国家面临的危难，他甘愿献出自己的生命；他把死亡看得像回家一样平常。这句写得好，一个“忽”字把视死如归的豪迈气概表现得淋漓尽致，展现出少年英雄忠勇无畏、为国献身的崇高精神。`, interpretation: `这首诗写于三国时期，曹植的哥哥曹丕刚当上皇帝，他心怀报国之志却无处施展，于是借一个少年英雄的形象表达心愿。诗中最精彩的是「白马饰金羁」——一匹白马配上金马鞍，多么英武帅气！少年骑着它冲向战场，把为国家牺牲看得像回家一样平常。这种豪迈的气概和强烈的爱国情怀，让这首诗成为千古名篇，激励了一代又一代中国人。尤其是「视死忽如归」这句，至今读来仍让人热血沸腾！` }] },
  { id: 69, title: "行路难（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "金樽清酒斗十千，玉盘珍羞直万钱，停杯投箸不能食，拔剑四顾心茫然，长风破浪会有时，直挂云帆济沧海",
    tags: "唐,励志",
    color: "#f59e0b",
    sections:[    { id: 1, title: "行路难（节选）", original: `金樽清酒斗十千，玉盘珍羞直万钱。
停杯投箸不能食，拔剑四顾心茫然。
欲渡黄河冰塞川，将登太行雪满山。
闲来垂钓碧溪上，忽复乘舟梦日边。
行路难！行路难！多歧路，今安在？
长风破浪会有时，直挂云帆济沧海。`, translation: `金杯里装着的美酒，一斗就值十千钱。玉盘里盛着的佳肴，价值更是高达万钱。可是我却放下酒杯，扔掉筷子，什么也吃不下去。拔出宝剑，朝着四面八方张望，心里却感到一片茫然。想要渡过黄河吧，冰雪却冻结了河流；想要登上太行山吧，大雪又封住了山峰。唉，总有一天，我会乘着长风破浪前行，到那时，我定要高高挂起云帆，径直渡过那浩瀚的大海！`, interpretation: `这是李白在仕途受挫、被迫离开长安时写的。诗人满腹才华却报国无门，心情郁闷极了。诗里有两样特别有意思的意象：一是“冰塞黄河”“雪满太行”，表面写自然，其实是他心里觉得前路全被堵住了；二是“长风破浪”“云帆济海”，这是他最出名的句子之一，鼓励了无数遇到困难的朋友！一千多年来，每次有人觉得撑不下去了，都会想起这两句——再难的路，也一定会有云开月明的那一天。` }] },
  { id: 70, title: "梦游天姥吟留别（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "安能摧眉，折腰事权，贵使我不，得开心颜",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "梦游天姥吟留别（节选）", original: `世间行乐亦如此，古来万事东流水。
别君去兮何时还，且放白鹿青崖间。
须行即骑访名山，安能摧眉折腰事权贵，使我不得开心颜。`, translation: `人世间的欢乐也像梦一样，古往今来所有事情都像东流的水一去不回头。我要离开你们了，什么时候才能回来呢？先把白鹿放养在青翠的山崖之间，想要出行的时候就骑着它去寻访名山。怎么能低头弯腰去伺候那些有权有势的人，让我心里不高兴呢？`, interpretation: `这是李白被权贵排挤出京后，在东鲁将要南游时写下的一首长诗的结尾。他把人世的富贵看作一场梦，认为万事像流水一样不可挽留，所以决心骑上白鹿去游历四方。这几句最厉害的就是最后那句'安能摧眉折腰事权贵，使我不得开心颜'——我怎么能够低眉弯腰去巴结当官的，让自己不开心呢！这种不向权贵低头的傲气，影响了后来很多文人，成了千古传诵的名句。` }] },
  { id: 71, title: "闻王昌龄左迁龙标遥有此寄",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "杨花落尽子规啼，闻道龙标过五溪，我寄愁心与明月，随君直到夜郎西",
    tags: "唐,送别",
    color: "#f59e0b",
    sections:[    { id: 1, title: "闻王昌龄左迁龙标遥有此寄", original: `杨花落尽子规啼，闻道龙标过五溪。
我寄愁心与明月，随君直到夜郎西。`, translation: `同学们，我们来读一读李白这首《闻王昌龄左迁龙标遥有此寄》。这首诗是李白听说好朋友王昌龄被贬到偏远的龙标之后写的，寄托了他对朋友深深的牵挂之情。

第一句“杨花落尽子规啼”：杨花也就是柳絮，已经飘落得干干净净；子规就是杜鹃鸟，它在树上不停地啼叫，仿佛在说“不如归去”。这两样景物写出了暮春时节的凄凉，也烘托出诗人心中愁苦的氛围。这句写得好，用景物悄悄带出了离别的伤感。

第二句“闻道龙标过五溪”：我听说了，你被贬到龙标去，一路上要经过五条溪流，路途遥远而又艰难困苦。

第三、四句“我寄愁心与明月，随君直到夜郎西”：我把满心的思念和忧愁都托付给天上的明月吧，让它伴随着你，一直走到夜郎的西边。连月亮都成了诗人的信使，这份牵挂真是又浪漫又深情。`, interpretation: `这首诗写于唐玄宗天宝年间，当时李白听说好友王昌龄被贬到偏远的龙标（今湖南怀化），心中十分牵挂。诗里有两个特别美的意象：飘落的杨花和啼叫的子规（杜鹃），杨花让人想到漂泊无依，杜鹃的叫声在古诗里常代表伤心。'我寄愁心与明月'是千古名句，李白把自己的思念托付给月亮，让月亮陪着朋友走完远路，浪漫又温暖。这种把月亮当作信使的写法，后来很多人都在学呢！` }] },
  { id: 72, title: "古朗月行（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "小时不识月，呼作白玉盘，又疑瑶台镜，飞在青云端",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "古朗月行（节选）", original: `小时不识月，呼作白玉盘。
又疑瑶台镜，飞在青云端。
仙人垂两足，桂树何团团。
白兔捣药秋复春，姮娥孤栖与谁怜。`, translation: `同学们，我们来读一读唐代大诗人李白的《古朗月行》。这首诗写的是李白小时候看月亮的情景。那时候他还小，不认识天上的月亮，所以把它叫作白色的玉盘。这里“白玉盘”是说月亮又圆又亮，就像洁白的玉石做成的大圆盘。接着他又怀疑，月亮也许是神仙住的瑶台里的一面镜子，这句写得好，一个疑问让我们仿佛也跟着他一起猜想。最后说镜子飞啊飞，挂在了高高的云端。短短四句，把小时候的天真可爱写得活灵活现，也让我们看到李白从小就有丰富的想象力。`, interpretation: `这是李白小时候的一首小诗，写于盛唐时期，那是个连诗人都爱幻想的浪漫年代。诗中用了两个特别美的意象——白玉盘和瑶台镜，把圆圆的月亮比作吃饭的玉盘，又比作神仙用的镜子，想象大胆又可爱。最妙的是一个"飞"字，月亮好像长了翅膀一样飘到云端，童趣十足。这首诗后来常被选进儿童启蒙读物，连大人都觉得"呼作白玉盘"这一句天真得让人发笑又让人羡慕。` }] },
  { id: 73, title: "把酒问月（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "青天有月来几时，我今停杯一问之，人攀明月不可得，月行却与人相随",
    tags: "唐,哲理",
    color: "#f59e0b",
    sections:[    { id: 1, title: "把酒问月（节选）", original: `青天有月来几时？我今停杯一问之。
人攀明月不可得，月行却与人相随。`, translation: `同学们，今天我们来读李白的一首小诗《把酒问月》的开头四句。诗人端起酒杯，仰望着夜空中的明月，忽然产生了天真的疑问：第一句"青天有月来几时"，是说青天上挂着这一轮明月，它究竟是从什么时候起就挂在那儿的呢？这可真是个有趣的问题呀。第二句"我今停杯一问之"，意思是诗人李白现在停下手中的酒杯，要亲自去问一问月亮。这个"问"字用得多好，写出了诗人孩童般的好奇心。接着第三句"人攀明月不可得"，是说人想要攀上青天去摘下月亮，那是不可能做到的事。最后一句"月行却与人相随"，笔锋一转，说虽然我们摘不到月亮，可月亮却会跟着人一起移动，不管你走到哪里，它都仿佛在陪伴着你。这句写得好，写出了月亮对人的温柔相随，是诗中很动人的名句。`, interpretation: `这是李白《把酒问月》中最有名的一段。李白在月亮下端着酒杯，忽然对天上的月亮产生了好奇：月亮是什么时候有的呢？于是他停下酒杯，认认真真地向月亮发问。接着他发现了一个有趣的现象——人想爬到月亮上去够不着，但月亮却像好朋友一样，你走到哪儿它就跟到哪儿。这首诗写于盛唐时期，李白一生爱月亮、写月亮，这首就是他对着月亮一边喝酒一边思考人生的名篇。它最厉害的地方是把"问月"写得又浪漫又有哲理，让小朋友也能感受到：原来抬头看月亮，也可以是一件很有诗意的事。` }] },
  { id: 74, title: "月下独酌（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "花间一壶酒，独酌无相亲，举杯邀明月，对影成三人",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "月下独酌（节选）", original: `花间一壶酒，独酌无相亲。
举杯邀明月，对影成三人。
月既不解饮，影徒随我身。
暂伴月将影，行乐须及春。`, translation: `同学们，我们来读一读李白这首有趣的诗。诗人在花丛中间摆下一壶香喷喷的美酒，可是身边没有一个亲近的朋友，只能自个儿自斟自饮，多么孤单呀！于是他举起酒杯，朝着天上的明月发出邀请：请明月下来陪我喝一杯吧！这时候，神奇的事情发生了——月光照在地上，映出了他自己的影子。这样一来，明月、影子和我自己，咱们仨就凑成了一桌！大家看，这句写得好，李白用丰富的想象，把孤单变成了一件好玩的事情。`, interpretation: `这首诗写于一个安静的夜晚，李白一个人喝酒觉得很孤单。可他是个乐天派呀，想了个绝妙的主意：把天上的月亮和自己的影子拉来当朋友，一下子变成“三个人”喝酒了！这种丰富的想象力是李白诗歌最迷人的地方。他明明很孤独，却写出了热闹又有趣的感觉，让人读着读着就笑了。这几句诗流传了一千多年，小朋友写作文时也可以学学这种“变无聊为有趣”的妙招哦！` }] },
  { id: 75, title: "登金陵凤凰台",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "凤凰台上凤凰游，凤去台空江自流，吴宫花草埋幽径，晋代衣冠成古丘",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "登金陵凤凰台", original: `凤凰台上凤凰游，凤去台空江自流。
吴宫花草埋幽径，晋代衣冠成古丘。
三山半落青天外，二水中分白鹭洲。
总为浮云能蔽日，长安不见使人愁。`, translation: `凤凰台上，曾经有凤凰鸟儿来游玩。凤凰飞走了，台上空空荡荡，只有长江水独自流淌。当年吴国的宫殿已经倒塌，花草野藤掩埋了幽静的小路。晋代的达官贵人们，也都变成了一座座古坟。都是因为天上的浮云遮住了太阳，站在这里看不见长安城，真让人心里发愁啊。`, interpretation: `这是李白在仕途不顺、离开长安后，登临金陵凤凰台时写下的诗。当时他被排挤出朝廷，怀才不遇，心中十分苦闷。诗中借凤凰台、长江、吴国宫殿、晋代古墓等景象，感慨繁华终会消逝、英雄也会老去。"总为浮云能蔽日"一句，巧妙地借用"浮云遮日"来比喻奸臣当道，遮挡了贤臣。这首诗对仗工整，气势雄浑，被誉为李白登临之作中可与崔颢《黄鹤楼》比肩的千古名篇。` }] },
  { id: 76, title: "子夜吴歌·秋歌",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "长安一片月，万户捣衣声，秋风吹不尽，总是玉关情，何日平胡虏，良人罢远征",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "子夜吴歌·秋歌", original: `长安一片月，万户捣衣声。
秋风吹不尽，总是玉关情。
何日平胡虏，良人罢远征。`, translation: `同学们好，我们来读一读这首《子夜吴歌·秋歌》。这是唐代大诗人李白写的一首思妇诗，诗中描写了月光下妇女思念远方丈夫的情景。一轮明月高高挂在长安城的上空，千家万户的院子里都传来妇女们捣洗衣服的声响。这捣衣声，是她们为远在边关的亲人赶制寒衣。凉爽的秋风吹啊吹，却怎么也吹不尽妇女们对玉门关外亲人的思念之情。这句写得好，用“吹不尽”三字，把无形的思念写得绵长无尽。什么时候才能平定北方的胡人，让我的丈夫不用再奔赴遥远的战场，早日平安归来呢？`, interpretation: `这首诗写于盛唐时期，是李白乐府诗中的名篇。诗人借秋夜捣衣的声响，描绘了长安城里妻子们思念远方丈夫的深情。捣衣声声、月光皎洁、秋风阵阵，这些意象交织在一起，勾勒出一幅思妇盼归的动人画面。诗中既有对征人远征的担忧，也有对和平生活的渴望，最后两句直抒胸臆，问出了千万百姓的心声。这首诗语言质朴、情感真挚，尤其是'长安一片月，万户捣衣声'两句，以明月和捣衣声营造出广阔而深远的意境，千百年来广为传诵。` }] },
  { id: 77, title: "宣州谢朓楼饯别校书叔云（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "弃我去者昨日之日不可留乱我心者今日之日多烦忧抽刀断水水更流举杯消愁愁更愁",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "宣州谢朓楼饯别校书叔云（节选）", original: `弃我去者，昨日之日不可留。
乱我心者，今日之日多烦忧。
长风万里送秋色，对此可以酣高楼。
蓬莱文章建安骨，中间小谢又清发。
俱怀逸兴壮思飞，欲上青天览明月。
抽刀断水水更流，举杯消愁愁更愁。
人生在世不称意，明朝散发弄扁舟。`, translation: `抛弃我而去的，是昨天的日子，昨天已经过去，留也留不住。扰乱我内心的，是今天的日子，今天又有太多烦恼和忧愁。万里长风把秋天的景色送来，面对这样的景色，我可以在高楼上畅快地喝酒。抽出刀来想斩断流水，水却流得更快；举起酒杯想消除愁苦，愁苦却变得更多。人生在世上，如果不能称心如意，不如明天就披散头发，驾着小船归隐江湖去吧。`, interpretation: `这是李白在宣州谢朓楼上为叔叔李云送别时写的诗。他一生渴望当大官、做大事，可总是不如愿，心里特别烦闷。诗里有两个特别有名的比喻：把愁比作流水，说拿刀去砍，水反而流得更急；举杯想借酒消愁，愁反而更多。小朋友有没有过这种感觉？越想忘掉一件不开心的事，它越忘不掉！不过李白最厉害的地方在于——他不只是叹气，最后一句忽然飞起来：管它呢，大不了明天披着头发去划船玩！这种从郁闷到洒脱的大转弯，就是李白诗歌最迷人的地方。` }] },
  { id: 78, title: "从军行",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "百战沙场碎铁衣，城南已合数重围，突营射杀呼延将，独领残兵千骑归",
    tags: "唐,战争",
    color: "#f59e0b",
    sections:[    { id: 1, title: "从军行", original: `百战沙场碎铁衣，城南已合数重围。
突营射杀呼延将，独领残兵千骑归。`, translation: `同学们，我们来读一读唐代诗人李贺的《从军行》。这首诗短短四句，描写了一位英勇的将军在战场上以少胜多、突围而归的故事。现在我们逐句来看：前两句写的是战况——战士们在战场上身经百战，铠甲都被刀枪砍得破碎了；可敌人已经布下好几层包围圈，把城南紧紧围住。读到这儿，你会不会替他们捏一把汗呢？后两句就是最精彩的部分了：这位将军毫无惧色，猛然冲进敌营，搭弓射箭，一举杀死了敌方的将领呼延。呼延是古代北方少数民族常见的姓氏，这里指敌军的主将。这句写得好，一个“突”字，就把将军的勇猛和果断展现得淋漓尽致。最后，他并没有恋战，而是独自带领剩下的一千多名骑兵，从重重包围中杀出了一条血路，平安归营。这位孤胆英雄的形象，是不是让你心生敬佩？这首诗的妙处，就在于用极短的篇幅，写出了一场惊心动魄的战斗，令人回味无穷。`, interpretation: `这首诗写于唐代，边疆战事频繁，许多将士奔赴沙场保家卫国。李白虽以浪漫诗闻名，但这首边塞诗却充满英雄气概。诗中最精彩的是'突营射杀'四个字——只见诗人笔下的大将如天神下凡，单枪匹马冲入敌阵，一箭射杀敌方首领呼延将，然后带着仅剩的千人骑兵从容突围。这是何等豪迈！短短四句，既有沙场厮杀的紧张，又有胜利归来的从容，'独领残兵千骑归'一句更是流传千古，成为描写英雄孤胆的经典名句。小朋友们读这首诗，闭上眼睛，是不是能想象出那位将军策马奔腾的威风模样？` }] },
  { id: 79, title: "丁督护歌",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "云阳上征去，两岸饶商贾，吴牛喘月时，拖船一何苦",
    tags: "唐,民生",
    color: "#f59e0b",
    sections:[    { id: 1, title: "丁督护歌", original: `云阳上征去，两岸饶商贾。
吴牛喘月时，拖船一何苦。
水浊不可饮，壶浆半成土。
一唱督护歌，心摧泪如雨。
万人凿磐石，无由达江浒。
君看石芒砀，掩泪悲千古。`, translation: `同学们，我们来读一读。这首诗是唐代大诗人李白写的《丁督护歌》，讲的是古代拉船纤夫的辛苦生活。一二两句的意思是：从云阳坐船向北，沿着长江逆流而上，去服劳役。河的两岸住着许多做生意的有钱人，家里很富足。三四两句的意思是：天气炎热的时候，连吴地的水牛热得都对着月亮喘气（这是古人常用的典故，叫“吴牛喘月”，说的是牛怕热，看到月亮以为是太阳，就害怕地喘起气来），可我这拉船的苦役，真是苦得没法说呀！这两岸的有钱人过得舒舒服服，而拉船的人却累死累活，这句写得好，一个“一何苦”，说出了多少纤夫心里的苦和泪。`, interpretation: `这首诗是李白在唐玄宗天宝年间游历江苏时写的。诗很短，只有四句，却充满了对劳动人民的深深同情。当时朝廷征调百姓去服役运船，无论酷暑寒冬都得拖船前行。两岸的商贾有钱悠闲，岸上拖船的人却被热浪折磨得喘不过气，反差特别强烈。诗人用“吴牛喘月”这个巧妙的细节，把暑热难耐写得生动极了，让人一下子就能感受到那种辛苦。短短二十个字，却写尽了底层劳动者的辛酸，是李白诗歌中难得的关心民生疾苦的作品。` }] },
  { id: 80, title: "关山月（节选）",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "明月出天山，苍茫云海间，长风几万里，吹度玉门关",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "关山月（节选）", original: `明月出天山，苍茫云海间。
长风几万里，吹度玉门关。
汉下白登道，胡窥青海湾。
由来征战地，不见有人还。
戍客望边色，思归多苦颜。
高楼当此夜，叹息未应闲。`, translation: `同学们，我们来读一读这首《关山月》。这是唐代大诗人李白写的一首边塞诗，描写的是戍守边关的将士们看到月亮时的心情。第一句“明月出天山”，是说一轮明亮的月亮从祁连山那边慢慢升起来了。这里的“天山”指的就是祁连山，那里常年云雾缭绕。第二句“苍茫云海间”，苍茫就是辽阔无边的样子，月亮穿行在一片又一片茫茫的云海之中，显得又圆又亮。这句写得好，把边塞的天空写得又高又远，让人心胸也跟着开阔起来。后两句“长风几万里，吹度玉门关”，是说浩浩荡荡的长风从万里之外吹来，一直吹过了遥远的玉门关。诗人用“几万里”来形容风走得远，让我们好像真的感受到了那股从远方吹来的风。整首诗短短四句，却把边塞的月夜写得又壮美又苍凉，真是千古名句。`, interpretation: `这首诗写于盛唐时期，那时候许多诗人都有立功边疆的志向，李白也不例外。诗里有三个特别美的画面：圆月、雪山、云海，一开头就像一幅水墨画铺在眼前。"长风几万里"这个"几万里"用得特别妙，把春风写得又远又有劲儿，好像风儿真的能飞越整个大唐的疆土呢！短短四句，没有一个"思乡"的字，却让人忍不住想家，这就是李白的高明之处。后来"长风几万里，吹度玉门关"常被人引用来形容壮志豪情。` }] },
  { id: 81, title: "望岳",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "会当凌绝顶，一览众山小",
    tags: "唐,励志",
    color: "#f59e0b",
    sections:[    { id: 1, title: "望岳", original: `岱宗夫如何？齐鲁青未了。
造化钟神秀，阴阳割昏晓。
荡胸生曾云，决眦入归鸟。
会当凌绝顶，一览众山小。`, translation: `巍峨的泰山到底有多雄伟呢？它苍翠的山色在齐鲁两地都望不尽。大自然把神奇和秀丽都集中到了这里，山峰的向阳一面明亮如清晨，背阴一面昏暗似傍晚，截然不同。山间层云升腾令人胸怀激荡，极目远眺，归林的飞鸟也映入眼帘。一定要登上泰山的顶峰，那时俯瞰群山，众山都会显得矮小。`, interpretation: `这首诗是杜甫二十四岁时漫游齐鲁地区所作，正是他年轻气盛、充满抱负的时期。全诗以一个'望'字贯穿，却不写登山，只写远望中的泰山，想象登顶的景象。诗人用'割'字写山势的高大，把山南山北的明暗分成两个世界，最妙的是最后两句'会当凌绝顶，一览众山小'，表达了年轻人敢于攀登高峰、俯视一切的雄心壮志。这两句后来成了千古名句，激励着无数人勇敢向前，挑战自我。整首诗没有一句'愁'字，处处洋溢着青年杜甫的豪情与自信。` }] },
  { id: 82, title: "蜀相",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "出师未捷身先死，长使英雄泪满襟",
    tags: "唐,怀古",
    color: "#f59e0b",
    sections:[    { id: 1, title: "蜀相", original: `丞相祠堂何处寻？锦官城外柏森森。
映阶碧草自春色，隔叶黄鹂空好音。
三顾频烦天下计，两朝开济老臣心。
出师未捷身先死，长使英雄泪满襟。`, translation: `丞相的祠堂到哪里去找呢？就在锦官城外，柏树长得高大茂密的地方。绿草映照着台阶，一年春天自己来到；黄鹂隔着树叶白白地唱着好听的歌。刘备三次拜访他，商量的是统一天下的大计；辅佐两代君主，开创和守卫国家，是老臣的一片忠心。可惜他出兵打仗还没取得胜利，自己就先病死了。这让后代的英雄们想起来，常常眼泪沾湿了衣襟。`, interpretation: `这首诗写于杜甫客居成都的时候，那时他正过着漂泊困苦的生活。听说武侯祠就在城外，他便去寻访，写下这首诗。诗里有三个特别重要的画面：高大的柏树、空自鸣叫的黄鹂和让人落泪的祠堂。柏树象征诸葛亮伟大的品格永远长青；黄鹂叫声虽好听，却无人欣赏，比喻世人并不真正理解他。杜甫特别擅长用这种“热闹反衬孤独”的写法，前面写得越安静，后面英雄的眼泪就越让人心酸。‘出师未捷身先死，长使英雄泪满襟’这两句成了千古名句，每当人们想起那些尽心尽力、却没能完成心愿的人，都会想起这两句诗。` }] },
  { id: 83, title: "江村",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "多病所须唯药物，微躯此外更何劳",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "江村", original: `清江一曲抱村流，长夏江村事事幽。
自去自来梁上燕，相亲相近水中鸥。
老妻画纸为棋局，稚子敲针作钓钩。
多病所须唯药物，微躯此外更何劳。`, translation: `同学们，我们来读一读唐代大诗人杜甫的《江村》。这首诗写的是夏日里一个小村庄的宁静景象，处处透露出悠闲自在的气息。我们先看第一句：清澈的江水弯弯曲曲地绕着村子静静地流淌，一个“抱”字用得特别生动，好像江水温柔地拥抱着整个村庄。第二句说，在漫长的夏日里，这个江边的小村庄里每件事情都显得安闲宁静，没有烦恼，没有喧嚣。接着，诗人把目光投向身边的小动物：屋梁上的燕子自由自在地飞来飞去，想停就停，想走就走，多么无忧无虑；再看水中的鸥鸟，它们成双成对地相互依偎，贴近彼此，嬉戏玩耍。这句写得好呀，短短七个字就把鸟儿的亲密与自在表现得活灵活现。整首诗虽没有一个热闹的场景，却让我们感受到乡村生活中那份平和的幸福。`, interpretation: `这首诗写于杜甫晚年定居成都草堂时期，那时安史之乱已经结束，诗人终于过上了一段相对安定的生活。诗中描绘了一个宁静祥和的江边小村：清澈的江水环绕村庄，夏日漫长却悠闲自得，燕子自由飞舞，鸥鸟相伴成趣。核心意象是"清江""梁燕""水鸥"，处处透着人与自然的和谐。艺术上以白描手法写景，朴素自然却意境悠远。这首《江村》是杜甫难得的闲适之作，展现了诗圣在历经战乱沧桑后，对平凡安宁生活的珍惜与热爱，也让后人看到一代诗圣温柔平和的一面。` }] },
  { id: 84, title: "兵车行（节选）",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "车辚辚马萧萧行人弓箭各在腰间君不见青海头古来白骨无人收",
    tags: "唐,战争",
    color: "#f59e0b",
    sections:[    { id: 1, title: "兵车行（节选）", original: `车辚辚，马萧萧，行人弓箭各在腰。
耶娘妻子走相送，尘埃不见咸阳桥。
牵衣顿足拦道哭，哭声直上干云霄。
道旁过者问行人，行人但云点行频。
或从十五北防河，便至四十西营田。
去时里正与裹头，归来头白还戍边。
边庭流血成海水，武皇开边意未已。
君不见，青海头，古来白骨无人收。
新鬼烦冤旧鬼哭，天阴雨湿声啾啾。`, translation: `战车轰隆隆地响，战马萧萧地叫，出征的士兵们把弓箭都挂在腰上。亲人们扯着衣服、跺着脚，拦在路中间放声大哭。哭声一直冲上了高高的云霄。你没看见吗？青海湖边那古战场上，从来都是白骨遍地没人收拾。新战死的鬼魂在诉说冤屈，旧战死的鬼魂也在哭嚎。到了阴天下雨的时候，就会听到鬼魂们啾啾地哭泣。`, interpretation: `这首诗写于唐朝天宝年间，那时候唐玄宗不断发动边境战争，老百姓被强行征召去打仗，亲人分别时哭得撕心裂肺。杜甫用“车辚辚、马萧萧”开头，光是声音就让人感到紧张；接着“牵衣顿足拦道哭”，七个字里有人物的动作和悲痛，画面感特别强。后半段从眼前送别转到青海古战场，借鬼哭来写战争的残酷，真是又可怕又让人心疼。这首诗最大的特点是用百姓的哭声说真话，所以被称为“诗史”，意思是杜甫的诗就像历史一样真实。后世写战争苦难的诗，很多都受了它的影响。` }] },
  { id: 85, title: "羌村三首（节选）",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "峥嵘赤云西，日脚下平地，柴门鸟雀噪，归客千里至",
    tags: "唐,叙事",
    color: "#f59e0b",
    sections:[    { id: 1, title: "羌村三首（节选）", original: `峥嵘赤云西，日脚下平地。
柴门鸟雀噪，归客千里至。
妻孥怪我在，惊定还拭泪。
世乱遭飘荡，生还偶然遂。
邻人满墙头，感叹亦歔欷。
夜阑更秉烛，相对如梦寐。`, translation: `西边天空中翻卷着层层叠叠像山一样高的红云，太阳光从云缝里射下来，平地上洒满了光辉。柴门前鸟儿叽叽喳喳地叫个不停，原来是漂泊千里的人终于回家了。妻子和孩子们看到我竟然还活着，又惊讶又奇怪，等心情平静下来，又忍不住擦去惊喜的泪水。在这兵荒马乱的年代里四处漂泊，能够活着回来，实在是偶然的幸运啊。`, interpretation: `这首诗写于公元757年，那时安史之乱已经爆发两年多，杜甫历尽艰险终于回到家中。诗中最动人的是家人的反应：先是惊讶——怎么还活着？再是拭泪——原来是高兴的泪水。短短几行字，把战乱中普通百姓的悲欢写得让人鼻子发酸。“妻孥怪我在，惊定还拭泪”成了千古名句，因为它说出了一个朴素的真理：和平年代回家是平常事，乱世里活着回家就是奇迹。杜甫最了不起的地方，就是能把这种真实的小情感写得那么动人。` }] },
  { id: 86, title: "阁夜",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "岁暮阴阳催短景，天涯霜雪霁寒宵，五更鼓角声悲壮，三峡星河影动摇",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "阁夜", original: `岁暮阴阳催短景，天涯霜雪霁寒宵。
五更鼓角声悲壮，三峡星河影动摇。
野哭几家闻战伐，夷歌数处起渔樵。
卧龙跃马终黄土，人事依依漫寂寥。`, translation: `一年到了尽头，白天越来越短，黑夜却越来越长。
在这偏远的地方，寒冷的夜晚，雪停了，霜也化了。
五更天的时候，战鼓声和号角声响起，声音是那样悲壮。
抬头看，三峡上空的银河和星星的影子，随着水波一起轻轻摇晃。`, interpretation: `这首诗写在公元766年冬天，杜甫住在夔州。那时候他年纪大了，又生病，离开家乡很久，心里又愁又冷。诗里有一个特别有意思的地方：诗人听见的是打仗的鼓角声，看到的是天上摇晃的星星。地上的声音很悲壮，天上的影子在晃动——他把自己心里的不安，写进了天地之间。这首诗最厉害的就是把“小”和“大”放在一起：寒夜、霜雪是一点点大的；鼓角、星河是很大很大的。可是它们都让诗人觉得孤单又难过。后来“岁暮天寒”成了人们形容又冷又孤单的常用词，很多人都喜欢用。` }] },
  { id: 87, title: "长恨歌（节选）",
    author: "白居易",
    dynasty: "唐",
    category: "唐",
    summary: "回眸一笑百媚生，六宫粉黛无颜色，在天愿作比翼鸟，在地愿为连理枝，天长地久有时尽，此恨绵绵无绝期",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "长恨歌（节选）", original: `汉皇重色思倾国，御宇多年求不得。
杨家有女初长成，养在深闺人未识。
天生丽质难自弃，一朝选在君王侧。
回眸一笑百媚生，六宫粉黛无颜色。
春寒赐浴华清池，温泉水滑洗凝脂。
在天愿作比翼鸟，在地愿为连理枝。
天长地久有时尽，此恨绵绵无绝期。`, translation: `唐玄宗喜欢美人，想找一位倾国倾城的绝世佳人。统治天下这么多年，一直没能找到。天生美丽的人，怎么舍得让自己埋没呢？有一天，她被选进宫，来到了君王身边。她回头微微一笑，千娇百媚立刻显现，六宫里所有的妃子都失去了光彩。我们只愿在天上做那比翼双飞的鸟儿，在地上做那枝干相连的树枝。可是啊，天再长地再久也有尽头，这份思念的愁苦啊，却永远没有结束的时候。`, interpretation: `这首诗写于唐朝，写的是唐玄宗和杨贵妃的爱情故事。当时唐玄宗宠爱杨贵妃，后来安史之乱爆发，杨贵妃在马嵬坡离世，唐玄宗日夜思念。诗中最美的画面是“回眸一笑百媚生”，只一笑就让所有人黯然失色，想象力多丰富呀！而“天长地久有时尽，此恨绵绵无绝期”成了千古名句，意思是就算天地也有尽头，可这份遗憾却永远不会消失。后来很多戏剧、小说都从这个故事里取材，比如《长生殿》呢。` }] },
  { id: 88, title: "采莲曲",
    author: "白居易",
    dynasty: "唐",
    category: "唐",
    summary: "菱叶萦波荷飐风，荷花深处小船通，逢郎欲语低头笑，碧玉搔头落水中",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "采莲曲", original: `菱叶萦波荷飐风，荷花深处小船通。
逢郎欲语低头笑，碧玉搔头落水中。`, translation: `同学们好，我们来读一读这首《采莲曲》。菱叶漂浮在清清的水面上，随着波纹轻轻荡漾；荷叶呢，在微风的吹拂下舒展开来，摇摇摆摆，像在跳舞一样。这句写得好，一个“萦”字、一个“飐”字，把水边风中的勃勃生机全写出来了。接着往里看，荷花长得又密又深，在这片粉红色的花丛深处，有一只小船悄悄地穿行着，原来船上坐着一位采莲的姑娘。然后最有趣的一幕发生了：小船划出花丛，姑娘一抬头，哎呀，恰好遇见了自己朝思暮想的心上人儿！她正想开口和他说句话，可话还没说出口，脸就先红了，只好害羞地低下头，抿着嘴笑了一下。谁也没想到，这一低头一歪头，头上那支漂亮的碧玉簪子竟“扑通”一声滑落，掉进了清清的水中。这首小诗没有直接说姑娘心里有多喜欢，却用一支落水的簪子，把她的惊喜、娇羞和俏皮全都写活啦。`, interpretation: `这首小诗出自唐代大诗人白居易之手，写的是江南水乡采莲的场景。唐代江南水乡生活富足，少女们常在夏日划着小船去采莲，诗人便用细腻的笔触捕捉了一个有趣的小片段。诗中最妙的是“欲语低头笑”这五个字，把小姑娘见到意中人时又惊喜又害羞的模样写得活灵活现。整首诗短短四句，有菱叶、有荷花、有风、有水、有人，构成了一幅清新又俏皮的水乡风情画。“碧玉搔头落水中”成了经典名句，让人读了忍不住会心一笑。` }] },
  { id: 89, title: "少年行",
    author: "王维",
    dynasty: "唐",
    category: "唐",
    summary: "新丰美酒斗十千，咸阳游侠多少年，相逢意气为君饮，系马高楼垂柳边",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "少年行", original: `新丰美酒斗十千，咸阳游侠多少年。
相逢意气为君饮，系马高楼垂柳边。`, translation: `同学们，我们来读一读这首诗。诗的开头说：新丰这个地方出产的美酒香醇极了，一斗酒就要卖到一万钱那么贵。紧接着写咸阳城里四处游历的侠客们，他们大多正是朝气蓬勃的少年。后面两句更妙：这些少年侠客偶然在路边相逢，彼此觉得志趣相投、意气相合，于是二话不说，就拉上你一起开怀畅饮。喝完之后呢？他们把马拴在高楼旁边、垂柳依依的地方。这句写得好——一个“系”字，把少年豪迈洒脱、不拘小节的样子表现得淋漓尽致。整首诗没有用一个华丽的词，却让我们看到了盛唐少年自信飞扬、豪情万丈的动人风采。`, interpretation: `这首诗写于盛唐时期，当时国力强盛，百姓充满自信与豪情，年轻人尤其向往建功立业、行走江湖。诗中没有刀光剑影，却处处透着少年侠客的勃勃生气——美酒、骏马、高楼、垂柳，组成一幅明丽鲜亮的画面。艺术上，王维用"美酒""游侠""意气"几个词，就把少年的豪爽劲儿勾了出来，语言明快，节奏铿锵。"相逢意气为君饮"一句尤其传神，成了后世描写豪情相遇的经典名句，常被引用来表达知己相逢的痛快。` }] },
  { id: 90, title: "登乐游原",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "向晚意不适，驱车登古原，夕阳无限好，只是近黄昏",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "登乐游原", original: `向晚意不适，驱车登古原。
夕阳无限好，只是近黄昏。`, translation: `同学们，我们来读一读这首《登乐游原》，它出自晚唐大诗人李商隐之手，短短二十个字，却写出了千古名句。傍晚的时候，天色渐渐暗下来，我心里有些闷闷的，不太舒畅，于是就驾着马车，去登上长安城附近的乐游原散散心。哇！登高远眺，只见一轮红红的夕阳正挂在天边，那光芒铺满了整片天空，真是美得让人心醉。这句写得好——“夕阳无限好”，短短五个字，就把眼前壮丽的景色说尽了。可是诗人紧接着笔锋一转，轻轻叹了口气：这么美的景色，偏偏已经接近黄昏，太阳马上就要落下山去，美好的东西总是留不住，这是多么让人惋惜呀！`, interpretation: `这首诗写于李商隐晚年，当时唐朝已经快走到尽头，他心里装着很多忧国忧民的事，却没有人能理解他。一个傍晚，他心情不好，独自开车（那时候是马车哦）爬上乐游原想散散心。结果一抬头，看见了超级美的夕阳！可是这么美的景色，偏偏出现在快要天黑的时候，让人又惊喜又难过。后人最喜欢的就是最后两句——'夕阳无限好，只是近黄昏'，现在我们还经常用这两句诗来形容美好的事物总是特别短暂，要好好珍惜呢！` }] },
  { id: 91, title: "无题",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "相见时难别亦难，东风无力百花残，春蚕到死丝方尽，蜡炬成灰泪始干",
    tags: "唐,爱情",
    color: "#f59e0b",
    sections:[    { id: 1, title: "无题", original: `相见时难别亦难，东风无力百花残。
春蚕到死丝方尽，蜡炬成灰泪始干。
晓镜但愁云鬓改，夜吟应觉月光寒。
蓬山此去无多路，青鸟殷勤为探看。`, translation: `我们难得见上一面，分别时更是难舍难分。暮春时节，东风柔弱无力，百花已经凋残。春蚕直到死去，蚕丝才能吐完；蜡烛烧成了灰，蜡泪才会流干。清晨对镜梳妆，只担忧如云的鬓发渐渐变白；夜晚独自吟诗，应感到月光冷冷清清。蓬莱山离这里没有多少路程，但愿有青鸟使者，殷勤地替我前去探望。`, interpretation: `这首诗写于晚唐，那时候朝廷里党派争斗很厉害，李商隐心里苦闷，就把一腔真情写进了爱情诗里。诗里有几个特别美的意象：春蚕吐丝、蜡烛流泪，比喻爱一个人愿意付出一切，哪怕到死才肯罢休；蓬山是传说中海上的仙山，青鸟是西王母的信使，代表对心上人深深的思念。这两句“春蚕到死丝方尽，蜡炬成灰泪始干”后来成了千古名句，常被用来形容老师对学生无私的奉献、医生对病人的付出，或者人们对待事业的忠诚。这首诗最厉害的地方是“意在言外”，明明写的是爱情，却又像在说人生、说理想，难怪一千多年来人人都爱读它。` }] },
  { id: 92, title: "霜月",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "初闻征雁已无蝉，百尺楼高水接天，青女素娥俱耐冷，月中霜里斗婵娟",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "霜月", original: `初闻征雁已无蝉，百尺楼高水接天。
青女素娥俱耐冷，月中霜里斗婵娟。`, translation: `同学们，我们来读一读唐代诗人李商隐的《霜月》。这首诗写的是深秋夜晚的景象。首句“初闻征雁已无蝉”，意思是：刚刚听到远行的大雁向南飞去的叫声，蝉儿已经不再鸣叫了。一个“初”字，一个“已”字，写出季节变换得真快呀！第二句“百尺楼高水接天”，是说诗人登上百尺高楼向远处眺望，茫茫的水面一直连到了天边，这句写得好，把秋天江面的开阔写得十分壮观！第三句“青女素娥俱耐冷”，青女是神话里管霜雪的天神，素娥就是月宫里的嫦娥，她们都能忍受寒冷。最后一句“月中霜里斗婵娟”，意思是在月光和冷霜之中，她们比试着谁更美丽动人。这首诗歌颂了秋夜里耐寒而美丽的景象，读来让人感到清冷而又韵味十足。`, interpretation: `这首诗写于晚唐，李商隐借深秋夜晚的霜月之景，表达自己清高孤傲的情怀。当时诗人处境不佳，但他没有直接抱怨，而是用浪漫的想象来排遣愁绪。诗中最妙的是最后两句：霜神青女和月中嫦娥都“不怕冷”，在清冷的环境里争相比美。这种把寒冷写得美丽动人的手法，既展现了诗人高洁的品格，也让整首诗充满梦幻色彩。李商隐擅长用典故和想象，这首诗短短四句却意境开阔，是唐诗中写秋夜霜月的佳作。` }] },
  { id: 93, title: "从军行·其四",
    author: "王昌龄",
    dynasty: "唐",
    category: "唐",
    summary: "青海长云暗雪山，孤城遥望玉门关，黄沙百战穿金甲，不破楼兰终不还",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "从军行·其四", original: `青海长云暗雪山，孤城遥望玉门关。
黄沙百战穿金甲，不破楼兰终不还。`, translation: `同学们，我们来读一读唐代诗人王昌龄的《从军行·其四》。首句写青海湖上空，浓云层层叠叠，把远处的雪山都遮得暗暗的，一个“暗”字，写出了边塞天色阴沉、战事紧张的气氛。次句，战士们驻守在孤零零的城池之中，抬头远望，目光所及之处，正是远在边陲的玉门关，戍守之苦与思乡之情尽在其中。这句写得好，仅用“遥望”二字，便把孤城与玉门关的空间距离展现出来。后两句转入豪迈之音：在漫天黄沙中，战士们身经百战，铁甲都被磨穿了，但他们依然斗志昂扬。这里“楼兰”借指侵扰边境的敌人。诗人直言：只要敌人未灭，就绝不归还家乡！短短四句，既有边塞的苍凉，也有将士保家卫国的坚定誓言，令人动容。`, interpretation: `这首诗写于唐朝，那时候边境常常打仗，战士们要保家卫国。王昌龄用'青海''雪山''黄沙''孤城'这些边塞景物，画出了一幅又远又冷又孤凉的画面，让小朋友们闭上眼睛就能感受到边疆的艰苦。最厉害的是后两句——'黄沙百战穿金甲，不破楼兰终不还'，意思是打了一百场仗，铠甲都被射穿了，但战士们还是不后退，发誓不打败敌人绝不回家！这种又苦又勇敢的精神特别让人感动，后来'不破楼兰终不还'还成了千古名句，被很多人引用呢。` }] },
  { id: 94, title: "从军行·其五",
    author: "王昌龄",
    dynasty: "唐",
    category: "唐",
    summary: "大漠风尘日色昏，红旗半卷出辕门，前军夜战洮河北，已报生擒吐谷浑",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "从军行·其五", original: `大漠风尘日色昏，红旗半卷出辕门。
前军夜战洮河北，已报生擒吐谷浑。`, translation: `同学们，我们来读一读唐代诗人王昌龄的《从军行·其五》。这首诗描写的是边塞将士在沙漠中英勇作战并取得胜利的故事。第一句“大漠风尘日色昏”，意思是：在广阔无边的大沙漠里，大风卷起沙土飞扬，连天空中的太阳都被遮蔽，看上去昏昏沉沉的。同学们可以想象一下，那是一种多么苍茫又壮烈的景象啊！第二句“红旗半卷出辕门”，是说：战士们高举着战旗，红旗半卷着，迅速地走出了军营的大门，准备奔赴前线。第三句“前军夜战洮河北”，讲的是：先头部队的将士们昨天夜晚就在洮河的北岸和敌人展开了激烈的战斗。这句写得好，一个“夜”字，让我们感受到战斗的紧张和将士们的奋勇。最后一句“已报生擒吐谷浑”，是说：现在捷报已经传来，前方将士们活捉了敌人的首领吐谷浑，取得了重大胜利！整首诗虽然只有短短四句，却让我们感受到了边塞将士保家卫国的英雄气概，真是令人敬佩。`, interpretation: `这首诗写于盛唐时期，那时候唐朝国力强盛，边疆战事频繁，王昌龄多次去西北边塞，亲眼见过战场，所以写得特别真实生动。诗里有几个特别有画面感的词：漫天的'大漠风尘'、飞舞的'红旗'、夜色中的'洮河'，短短四句就像一部小电影，让人先看到出征时的紧张，再听到前线的战报。写法上最妙的是'不见战斗，只听捷报'，不写怎么打仗，反而更有气势！最后一句'已报生擒吐谷浑'成了千古名句，常被用来形容打了大胜仗，是小朋友写作文时也能用上的好句子哦。` }] },
  { id: 95, title: "采莲曲",
    author: "王昌龄",
    dynasty: "唐",
    category: "唐",
    summary: "荷叶罗裙一色裁，芙蓉向脸两边开，乱入池中看不见，闻歌始觉有人来",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "采莲曲", original: `荷叶罗裙一色裁，芙蓉向脸两边开。
乱入池中看不见，闻歌始觉有人来。`, translation: `碧绿的荷叶和姑娘的裙子像是同一块布裁出来的，颜色一模一样。粉红的荷花在姑娘脸颊两旁盛开，好像花儿对着她的脸笑。姑娘们划着小船进了荷花池，人和花混在一起，分不清哪个是花哪个是人啦。只能听到一阵阵歌声，才知道原来有人在这里采莲呢。`, interpretation: `这首诗写于盛唐时期，王昌龄借采莲的场景，描绘江南水乡的美丽画面。诗人没有直接写人有多美，而是用荷叶比作罗裙、用荷花比作笑脸，把人和自然融为一体，这就是"以景写人"的高明之处。"乱入池中看不见，闻歌始觉有人来"是千古名句，写得特别有趣——人藏进了花海里，只能靠歌声才能发现她们，画面感十足，让人好像也闻到了荷香、听见了歌声呢！` }] },
  { id: 96, title: "闺怨",
    author: "王昌龄",
    dynasty: "唐",
    category: "唐",
    summary: "闺中少妇不知愁，春日凝妆上翠楼，忽见陌头杨柳色，悔教夫婿觅封侯",
    tags: "唐,情感",
    color: "#f59e0b",
    sections:[    { id: 1, title: "闺怨", original: `闺中少妇不知愁，春日凝妆上翠楼。
忽见陌头杨柳色，悔教夫婿觅封侯。`, translation: `同学们，我们来读一读这首《闺怨》。深闺里的年轻妻子原本不知道什么是忧愁，春天到了，她精心梳妆打扮，登上翠绿的楼阁去赏景。忽然，她看见路边田埂上的杨柳已经抽出了嫩绿的新芽，这才勾起满心的惆怅，后悔当初不该让丈夫去边疆求取功名。这句写得好啊，一个“悔”字，把少妇的失落与孤单表现得淋漓尽致。全诗短短四句，却刻画了一位由无忧转为忧愁的思妇形象，道出了古往今来许多家庭因追逐功名而分离的无奈。`, interpretation: `这首诗写于盛唐时期，那时候许多男子都渴望建功立业、出人头地。诗人没有直接写思念，而是抓住一个瞬间：少妇打扮得漂漂亮亮去登楼，本是为了散心，可一看见路边的杨柳——那是古人送别时折来相赠的象征——心里顿时翻涌起对远行丈夫的思念。整首诗只写她从'不知愁'到'悔'的转变，可背后的孤独和牵挂全藏在里头了。尤其是'悔教夫婿觅封侯'一句，流传千年，成了表达思妇心情的经典名句。` }] },
  { id: 97, title: "燕歌行（节选）",
    author: "高适",
    dynasty: "唐",
    category: "唐",
    summary: "战士军前半死生，美人帐下犹歌舞，大漠穷秋塞草腓，孤城落日斗兵稀",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "燕歌行（节选）", original: `战士军前半死生，美人帐下犹歌舞。
大漠穷秋塞草腓，孤城落日斗兵稀。
身当恩遇常轻敌，力尽关山未解围。
铁衣远戍辛勤久，玉箸应啼别离后。
少妇城南欲断肠，征人蓟北空回首。
边庭飘飖那可度，绝域苍茫更何有。
杀气三时作阵云，寒声一夜传刁斗。
相看白刃血纷纷，死节从来岂顾勋。
君不见沙场征战苦，至今犹忆李将军。`, translation: `同学们，我们来看这几句诗。战士们在军队的前沿拼死作战，伤亡惨重，几乎有一半人献出了生命；可在将军的营帐里，美人却还在唱歌跳舞，仿佛外面的厮杀与她们毫无关系。这句写得好！一边是浴血奋战的士兵，一边是醉生梦死的享乐，对比多么鲜明！接着看，大沙漠到了深秋，边塞的草木已经枯萎发黄，一片萧瑟凄凉。孤零零的城池上，落日缓缓西沉，还能够拿起武器战斗的士兵越来越少。这几句诗既写出了边塞战场的悲壮，也暗暗批评了主帅只顾享乐、不体恤将士的作风。`, interpretation: `这首诗写于唐玄宗统治后期，那时候皇帝喜欢打仗，大将们却只顾自己享乐，不管士兵死活。诗人高适用“战士”和“美人”做对比，一个在前线拼命，一个在后营享乐，看得让人又心疼又生气！“大漠”“孤城”“落日”这些画面特别苍凉，让人觉得战场好悲壮。后来“战士军前半死生，美人帐下犹歌舞”成了千古名句，专门用来批评那些不顾士兵死活的人。` }] },
  { id: 98, title: "白雪歌送武判官归京（节选）",
    author: "岑参",
    dynasty: "唐",
    category: "唐",
    summary: "忽如一夜春风来，千树万树梨花开",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "白雪歌送武判官归京（节选）", original: `北风卷地白草折，胡天八月即飞雪。
忽如一夜春风来，千树万树梨花开。
散入珠帘湿罗幕，狐裘不暖锦衾薄。
将军角弓不得控，都护铁衣冷难着。
瀚海阑干百丈冰，愁云惨淡万里凝。
中军置酒饮归客，胡琴琵琶与羌笛。
纷纷暮雪下辕门，风掣红旗冻不翻。
轮台东门送君去，去时雪满天山路。
山回路转不见君，雪上空留马行处。`, translation: `北风呼啸着卷过大地，把白草都吹折了。西北边塞的天气，到了八月就开始下雪。这一夜，好像突然吹来了春风，一夜之间，千万棵梨树全都开满了白色的花。雪花飘进珠帘，打湿了丝绸帐幔。穿着狐皮大衣都不觉得暖和，锦缎被子也显得太薄了。山路曲折，绕来绕去，就看不见你的身影了。雪地上只留下你骑马走过的蹄印。`, interpretation: `这是唐代边塞诗人岑参的名篇，写于他送别朋友回长安的雪夜。诗人长期戍守边疆，熟悉那里的苦寒生活。开篇就让你感受边疆烈风大雪的厉害：八月就飞雪，连最好的狐裘锦被都挡不住寒冷。最妙的是中间四句——他不说雪花像什么，偏说像春风里盛开的梨花！这正是千古传诵的名句。春天象征温暖，梨花代表美好，诗人用最美的春景来形容冷酷的寒冬，正是边塞诗“以乐景写哀情”的绝妙手法。结尾目送朋友远去，只剩雪中蹄印，余味无穷。` }] },
  { id: 99, title: "送杜少府之任蜀州",
    author: "王勃",
    dynasty: "唐",
    category: "唐",
    summary: "海内存知己，天涯若比邻，无为在歧路，儿女共沾巾",
    tags: "唐,送别",
    color: "#f59e0b",
    sections:[    { id: 1, title: "送杜少府之任蜀州", original: `城阙辅三秦，风烟望五津。
与君离别意，同是宦游人。
海内存知己，天涯若比邻。
无为在歧路，儿女共沾巾。`, translation: `京城长安被三秦大地护卫着，（遥望）你要去的蜀州啊，只见一片风烟迷蒙。我和你就要分别了，心里有说不完的话；不过咱们都是出门做官的人，离别本是常事。只要四海之内有知心的朋友，哪怕相隔天涯，也会觉得像邻居一样亲近。咱们可不要在分手的路口，像小儿女那样哭哭啼啼、眼泪沾湿手帕呀。`, interpretation: `这是王勃二十岁不到时写给朋友杜少府的送别诗，地点在长安。诗人要去蜀地（四川）做官，王勃写诗为他送行。诗中有名句"海内存知己，天涯若比邻"，意思是真正的朋友即使远隔千山万水，心也贴得很近。这句诗之所以千古传唱，是因为它一扫送别诗里哭哭啼啼的愁绪，写得豪迈开朗、格局很大，把离别的伤感变成了友情的温暖。后人送别时常引用这两句，鼓励自己和朋友：天各一方，情谊不变。` }] },
  { id: 100, title: "滕王阁诗（节选）",
    author: "王勃",
    dynasty: "唐",
    category: "唐",
    summary: "落霞与孤鹜齐飞，秋水共长天一色",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "滕王阁诗（节选）", original: `滕王高阁临江渚，佩玉鸣鸾罢歌舞。
画栋朝飞南浦云，珠帘暮卷西山雨。
落霞与孤鹜齐飞，秋水共长天一色。`, translation: `滕王阁这座高高的楼阁，矗立在江边的小洲上。当年佩玉叮当、銮铃响彻的歌舞盛会，如今已经结束了。早晨，雕梁画栋间飘过南浦的白云。傍晚，珠串般的帘子卷起西山斜落的雨丝。天边的一抹晚霞与孤单的野鸭一起飞翔。秋天的江水和辽阔的天空融成了同一种颜色。`, interpretation: `这首诗写于唐朝初年，王勃二十多岁路过南昌，应朋友之邀在滕王阁上挥笔写下的。那时候的唐朝刚刚安定下来，文人们特别爱聚会、写诗。王勃用“南浦云”“西山雨”“落霞”“孤鹜”“秋水”“长天”这些画面，把秋天的傍晚写得又开阔又有点淡淡的感伤。特别是“落霞与孤鹜齐飞，秋水共长天一色”这两句，简直成了千古名句，连今天的语文课本都离不开它。后来很多人画画、写对联都要借用这两句，可见王勃有多厉害！` }] },
]
